EMBEDDED_SOURCE_GZ_B64 = """"""


def _decode_original_source() -> str:
    return gzip.decompress(base64.b64decode(EMBEDDED_SOURCE_GZ_B64)).decode("utf-8", errors="ignore")



def _extract_engine_source(full_source: str) -> str:
    """
    Keep the real processing engine and post-engine patches,
    but skip the giant Tkinter window construction block that starts at root = tk.Tk().
    This avoids desktop UI startup while preserving dedup/autofix/export logic.
    """
    lines = full_source.splitlines(keepends=True)
    pre_ui = lines[:3838]
    patch_part_1 = lines[8042:8160]
    patch_part_2 = lines[8182:8204]
    return "".join(pre_ui + patch_part_1 + patch_part_2)


class _DummyVar:
    def __init__(self, value=None):
        self._value = value
    def get(self):
        return self._value
    def set(self, value):
        self._value = value


class _DummyWidget:
    def __init__(self, *args, **kwargs):
        self._value = kwargs.get("value", "")
        self._values = []
        self._children = []
        self._dict = {}
    def __call__(self, *args, **kwargs):
        return self
    def __getattr__(self, name):
        def _method(*args, **kwargs):
            if name == "get":
                return self._value
            if name in ("selection", "curselection"):
                return ()
            if name == "get_children":
                return []
            return self
        return _method
    def __setitem__(self, key, value):
        self._dict[key] = value
    def __getitem__(self, key):
        return self._dict.get(key, None)
    def __iter__(self):
        return iter([])
    def __len__(self):
        return 0
    def cget(self, key):
        return self._dict.get(key, self._value if key == "text" else "")
    def winfo_children(self):
        return []
    def insert(self, *args, **kwargs):
        if args:
            self._value = args[-1]
        return self
    def delete(self, *args, **kwargs):
        self._value = ""
        return self
    def get(self, *args, **kwargs):
        return self._value
    def set(self, value):
        self._value = value
    def mainloop(self, *args, **kwargs):
        return None
    def after(self, *args, **kwargs):
        return None
    def pack(self, *args, **kwargs):
        return self
    def grid(self, *args, **kwargs):
        return self
    def place(self, *args, **kwargs):
        return self
    def bind(self, *args, **kwargs):
        return self
    def bind_all(self, *args, **kwargs):
        return self
    def configure(self, *args, **kwargs):
        return self
    config = configure
    def title(self, *args, **kwargs):
        return self
    def geometry(self, *args, **kwargs):
        return self
    def create_window(self, *args, **kwargs):
        return 1
    def itemconfig(self, *args, **kwargs):
        return self
    def yview(self, *args, **kwargs):
        return self
    def xview(self, *args, **kwargs):
        return self
    def set_values(self, values):
        self._values = list(values)
    def destroy(self):
        return None
    def protocol(self, *args, **kwargs):
        return None
    def update(self):
        return None
    def update_idletasks(self):
        return None
    def winfo_exists(self):
        return False


class _DummyFont:
    def configure(self, *args, **kwargs):
        return None


def _install_tkinter_shims():
    tk = types.ModuleType("tkinter")
    ttk = types.ModuleType("tkinter.ttk")
    messagebox = types.ModuleType("tkinter.messagebox")
    filedialog = types.ModuleType("tkinter.filedialog")
    tkfont = types.ModuleType("tkinter.font")

    widget_names = [
        "Tk", "Toplevel", "Frame", "Label", "LabelFrame", "Entry", "Button",
        "Canvas", "Scrollbar", "Spinbox", "Listbox", "Scale", "Checkbutton",
        "Progressbar", "Treeview", "Combobox"
    ]
    for name in widget_names:
        setattr(tk, name, _DummyWidget)
        setattr(ttk, name, _DummyWidget)

    tk.StringVar = _DummyVar
    tk.IntVar = _DummyVar
    tk.BooleanVar = _DummyVar
    tk.END = "end"

    # Common aliases some patched builds use.
    ttk.Style = _DummyWidget

    def _askopenfilename(*args, **kwargs):
        return ""
    def _asksaveasfilename(*args, **kwargs):
        return ""
    def _askdirectory(*args, **kwargs):
        return os.getcwd()

    filedialog.askopenfilename = _askopenfilename
    filedialog.asksaveasfilename = _asksaveasfilename
    filedialog.askdirectory = _askdirectory

    messagebox.showinfo = lambda *args, **kwargs: None
    messagebox.showwarning = lambda *args, **kwargs: None
    messagebox.showerror = lambda *args, **kwargs: None

    tkfont.nametofont = lambda *args, **kwargs: _DummyFont()

    tk.ttk = ttk
    tk.messagebox = messagebox
    tk.filedialog = filedialog
    tk.font = tkfont

    sys.modules["tkinter"] = tk
    sys.modules["tkinter.ttk"] = ttk
    sys.modules["tkinter.messagebox"] = messagebox
    sys.modules["tkinter.filedialog"] = filedialog
    sys.modules["tkinter.font"] = tkfont


@lru_cache(maxsize=1)
def load_engine():
    _install_tkinter_shims()
    source = _decode_original_source()
    module = types.ModuleType("fuel_subsidy_engine")
    module.__file__ = "embedded_fuel_subsidy_engine.py"
    exec(compile(source, module.__file__, "exec"), module.__dict__)
    return module


def _sanitize_filename(name: str) -> str:
    name = os.path.basename(name or "file.xlsx")
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", name)
    return name or "file.xlsx"


def _get_session_dir() -> Path:
    if "fuel_subsidy_streamlit_dir" not in st.session_state:
        st.session_state["fuel_subsidy_streamlit_dir"] = tempfile.mkdtemp(prefix="streamlit_dedup_")
    base = Path(st.session_state["fuel_subsidy_streamlit_dir"])
    (base / "uploads").mkdir(parents=True, exist_ok=True)
    (base / "exports").mkdir(parents=True, exist_ok=True)
    return base


def _save_upload(uploaded_file, slot: str) -> str:
    if uploaded_file is None:
        return ""
    base = _get_session_dir() / "uploads"
    safe_name = f"{slot}_{_sanitize_filename(uploaded_file.name)}"
    path = base / safe_name
    data = uploaded_file.getbuffer()
    with open(path, "wb") as f:
        f.write(data)
    return str(path)


def _safe_list_sheets(engine, path: str):
    if not path:
        return []
    try:
        return engine.list_excel_sheets(path)
    except Exception:
        try:
            xls = pd.ExcelFile(path)
            return list(xls.sheet_names)
        except Exception:
            return []


def _df_copy(df):
    if df is None:
        return None
    try:
        return df.copy()
    except Exception:
        return df



def _coerce_removed_logic_key(logic_key: str | None) -> str:
    logic_key = str(logic_key or "").strip()
    return logic_key or "__ignore__"


def _apply_age_limit_overrides(engine, enable_min_age: bool, min_age_limit: int, enable_max_age: bool, max_age_limit: int):
    engine.MIN_VALID_AGE = max(0, int(min_age_limit)) if enable_min_age else 0
    engine.MAX_VALID_AGE = max(0, int(max_age_limit)) if enable_max_age else 200


def _replace_age_reason_labels(df: pd.DataFrame, enable_min_age: bool, min_age_limit: int, enable_max_age: bool, max_age_limit: int):
    if df is None or getattr(df, "empty", True):
        return df
    reason_col = None
    for candidate in ("Lack_Reason", "FindingReason", "Reason"):
        if candidate in df.columns:
            reason_col = candidate
            break
    if reason_col is None:
        return df

    out = df.copy()
    series = out[reason_col].astype(str)
    if enable_min_age:
        series = series.str.replace("Below 18 years old", f"Below {int(min_age_limit)} years old", regex=False)
    else:
        series = series.str.replace("Below 18 years old", "", regex=False)
    if enable_max_age:
        series = series.str.replace("Above 85 years old", f"Above {int(max_age_limit)} years old", regex=False)
    else:
        series = series.str.replace("Above 85 years old", "", regex=False)

    series = (
        series.str.replace(r"\s*;\s*;\s*", "; ", regex=True)
              .str.replace(r"^\s*;\s*", "", regex=True)
              .str.replace(r"\s*;\s*$", "", regex=True)
              .str.replace(r"\s{2,}", " ", regex=True)
              .str.strip()
    )
    out[reason_col] = series
    return out


def _postprocess_age_reason_outputs(engine, results: dict, enable_min_age: bool, min_age_limit: int, enable_max_age: bool, max_age_limit: int):
    for attr in ("result_no_detail_a", "result_no_detail_b", "result_lack_ab"):
        current = getattr(engine, attr, None)
        patched = _replace_age_reason_labels(current, enable_min_age, min_age_limit, enable_max_age, max_age_limit)
        setattr(engine, attr, patched)

    if isinstance(results, dict):
        for key in ("lack_a", "lack_b", "lack_ab"):
            results[key] = _replace_age_reason_labels(results.get(key), enable_min_age, min_age_limit, enable_max_age, max_age_limit)
    return results


_DEDUP_LABEL_BY_TYPE = {
    "TRUE_DUPLICATE": "MATCH DEDUP",
    "FUZZ_DUPLICATE": "FUZZ DEDUP",
    "SWAP_TRUE_DUPLICATE": "SWAP_TRUE DEDUP",
    "SWAP_FUZZ_DUPLICATE": "SWAP_FUZZY DEDUP",
}

_DEDUP_SOURCE_PRIORITY = {
    "TRUE_DUPLICATE": 400,
    "SWAP_TRUE_DUPLICATE": 300,
    "FUZZ_DUPLICATE": 200,
    "SWAP_FUZZ_DUPLICATE": 100,
}

_DEDUP_MEMBER_PRIORITY = {
    "TRUE_DUPLICATE": 10,
    "FUZZ_DUPLICATE": 20,
    "SWAP_TRUE_DUPLICATE": 30,
    "SWAP_FUZZ_DUPLICATE": 40,
}


def _norm_col_key(value) -> str:
    return str(value).replace("_", "").replace(" ", "").lower()


def _find_column(df: pd.DataFrame, *normalized_names: str):
    if df is None or getattr(df, "empty", True):
        return None
    wanted = {_norm_col_key(name) for name in normalized_names if name}
    for col in df.columns:
        if _norm_col_key(col) in wanted:
            return col
    return None


def _coerce_float(value, default: float = 0.0) -> float:
    try:
        if pd.isna(value):
            return default
    except Exception:
        pass
    s = str(value).strip().replace("%", "").replace(",", "")
    if not s:
        return default
    try:
        return float(s)
    except Exception:
        return default


def _coerce_int(value, default: int = 10**9) -> int:
    try:
        if pd.isna(value):
            return default
    except Exception:
        pass
    s = str(value).strip().replace(",", "")
    if not s:
        return default
    try:
        return int(float(s))
    except Exception:
        return default


def _row_fill_score(row: pd.Series) -> int:
    ignore_norm = {
        "matchgroup", "grouporder", "matchrole", "matchtype", "duplicatetag",
        "duplicatereason", "reason", "conflictreason", "confidence", "similarityscore",
        "deduptype", "deduplabel", "source", "source2", "rowuid", "uniqueid",
        "finalgroup", "rolerank", "duptagrank"
    }
    score = 0
    for col, value in row.items():
        if _norm_col_key(col) in ignore_norm:
            continue
        if pd.isna(value):
            continue
        s = str(value).strip()
        if s:
            score += 1
    return score


def _dedup_source_sort_key(row: pd.Series, dedup_col, score_col, rownum_col):
    dedup_type = str(row.get(dedup_col, "") or "").strip().upper()
    return (
        _DEDUP_SOURCE_PRIORITY.get(dedup_type, 0),
        _coerce_float(row.get(score_col), 0.0),
        _row_fill_score(row),
        -_coerce_int(row.get(rownum_col), default=10**9),
    )


def _dedup_member_sort_key(row: pd.Series, dedup_col, score_col, rownum_col):
    dedup_type = str(row.get(dedup_col, "") or "").strip().upper()
    return (
        _DEDUP_MEMBER_PRIORITY.get(dedup_type, 999),
        -_coerce_float(row.get(score_col), 0.0),
        -_row_fill_score(row),
        _coerce_int(row.get(rownum_col), default=10**9),
    )


def _postprocess_single_dedup_df(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or getattr(df, "empty", True):
        return df

    group_col = _find_column(df, "Match_Group", "MatchGroup")
    if not group_col:
        return df

    dedup_col = _find_column(df, "DedupType")
    score_col = _find_column(df, "Similarity_Score", "SimilarityScore")
    role_col = _find_column(df, "Match_Role", "MatchRole")
    order_col = _find_column(df, "Group_Order", "GroupOrder")
    rownum_col = _find_column(df, "SourceRowNumber", "Source_Row_Number", "RowNumber", "Row_Number")

    out_groups = []
    for _, grp in df.groupby(group_col, sort=True, dropna=False):
        grp = grp.copy()
        if dedup_col is None:
            grp["DedupType"] = "TRUE_DUPLICATE"
            dedup_col = "DedupType"
        if score_col is None:
            grp["Similarity_Score"] = 0.0
            score_col = "Similarity_Score"
        if role_col is None:
            grp["Match_Role"] = ""
            role_col = "Match_Role"
        if order_col is None:
            grp["Group_Order"] = 0
            order_col = "Group_Order"
        if rownum_col is None:
            grp["__rownum_fallback"] = range(1, len(grp) + 1)
            rownum_col = "__rownum_fallback"

        source_idx = max(grp.index, key=lambda idx: _dedup_source_sort_key(grp.loc[idx], dedup_col, score_col, rownum_col))
        grp["Dedup_Label"] = grp[dedup_col].map(lambda v: _DEDUP_LABEL_BY_TYPE.get(str(v or "").strip().upper(), "FUZZ DEDUP"))
        grp.loc[source_idx, "Dedup_Label"] = "DEDUP SOURCE"
        grp[role_col] = grp["Dedup_Label"]

        source_row = grp.loc[[source_idx]]
        member_rows = grp.drop(index=source_idx)
        if not member_rows.empty:
            member_rows = member_rows.loc[
                sorted(
                    member_rows.index,
                    key=lambda idx: _dedup_member_sort_key(member_rows.loc[idx], dedup_col, score_col, rownum_col)
                )
            ]
        grp = pd.concat([source_row, member_rows], axis=0)
        grp[order_col] = list(range(1, len(grp) + 1))
        if "__rownum_fallback" in grp.columns:
            grp = grp.drop(columns=["__rownum_fallback"])
        out_groups.append(grp)

    out = pd.concat(out_groups, axis=0).reset_index(drop=True)
    cols = list(out.columns)
    if "Dedup_Label" in cols:
        anchor_after = None
        for candidate in (role_col, dedup_col, score_col):
            if candidate in cols:
                anchor_after = cols.index(candidate)
                break
        cols.remove("Dedup_Label")
        insert_at = (anchor_after + 1) if anchor_after is not None else 0
        cols.insert(insert_at, "Dedup_Label")
        out = out[cols]
    return out


def _postprocess_dedup_group_outputs(results: dict):
    if not isinstance(results, dict):
        return results
    for key in ("dup_ab", "dup_a", "dup_b", "cross_dup_ab"):
        results[key] = _postprocess_single_dedup_df(results.get(key))
    return results


def _clean_export_candidate_from_dup_row(row: pd.Series, clean_columns=None) -> dict:
    drop_norm = {
        "matchgroup", "grouporder", "matchrole", "matchtype", "duplicatetag", "deduptype",
        "deduplabel", "similarityscore", "similarityscorepct", "confidence", "reason",
        "duplicatereason", "conflictreason", "finalgroup", "rolerank", "duptagrank"
    }
    payload = {}
    for col, value in row.items():
        if _norm_col_key(col) in drop_norm:
            continue
        payload[col] = value
    if clean_columns:
        for col in clean_columns:
            payload.setdefault(col, pd.NA)
        payload = {col: payload.get(col, pd.NA) for col in clean_columns}
    return payload


def _merge_clean_export_rows_preserving_real_duplicates(clean_df: pd.DataFrame, survivor_df: pd.DataFrame) -> pd.DataFrame:
    if clean_df is None or getattr(clean_df, "empty", True):
        return survivor_df.reset_index(drop=True)
    if survivor_df is None or getattr(survivor_df, "empty", True):
        return clean_df.reset_index(drop=True)

    merged = pd.concat([clean_df, survivor_df], ignore_index=True)
    identity_candidates = [
        "_RowUID", "RowUID", "UniqueID", "NO.", "NO", "No.",
        "SourceRowNumber", "Source_Row_Number", "RowNumber", "Row_Number", "_Source"
    ]
    subset = [col for col in identity_candidates if col in merged.columns]
    if subset:
        merged = merged.drop_duplicates(subset=subset, keep="first", ignore_index=True)
    return merged.reset_index(drop=True)


def _promote_true_duplicate_survivors_for_export(engine):
    pairings = [
        ("result_dup_ab", "result_clean_ab"),
        ("result_dup_a", "result_clean_a"),
        ("result_dup_b", "result_clean_b"),
    ]
    exact_types = {"TRUE_DUPLICATE", "SWAP_TRUE_DUPLICATE"}

    for dup_attr, clean_attr in pairings:
        dup_df = getattr(engine, dup_attr, None)
        if dup_df is None or getattr(dup_df, "empty", True):
            continue

        group_col = _find_column(dup_df, "Match_Group", "MatchGroup")
        dedup_col = _find_column(dup_df, "DedupType")
        score_col = _find_column(dup_df, "Similarity_Score", "SimilarityScore")
        rownum_col = _find_column(dup_df, "SourceRowNumber", "Source_Row_Number", "RowNumber", "Row_Number")
        if not group_col or not dedup_col:
            continue

        survivors = []
        survivor_indices = []
        for _, grp in dup_df.groupby(group_col, sort=True, dropna=False):
            dedup_values = {str(v or "").strip().upper() for v in grp[dedup_col].tolist()}
            if not (dedup_values & exact_types):
                continue
            source_idx = max(grp.index, key=lambda idx: _dedup_source_sort_key(grp.loc[idx], dedup_col, score_col, rownum_col))
            survivor_indices.append(source_idx)
            survivors.append(dup_df.loc[source_idx])

        if not survivors:
            continue

        clean_df = getattr(engine, clean_attr, None)
        clean_columns = None if clean_df is None or getattr(clean_df, "empty", True) else list(clean_df.columns)
        survivor_payloads = [_clean_export_candidate_from_dup_row(row, clean_columns) for row in survivors]
        survivor_df = pd.DataFrame(survivor_payloads)

        clean_df = _merge_clean_export_rows_preserving_real_duplicates(clean_df, survivor_df)

        new_dup_df = dup_df.drop(index=survivor_indices).reset_index(drop=True)
        setattr(engine, clean_attr, clean_df.reset_index(drop=True))
        setattr(engine, dup_attr, new_dup_df)

    return engine



def _prefer_existing(value, fallback_func):
    return value if value is not None else fallback_func()


def _to_excel_bytes(df: pd.DataFrame, sheet_name: str = "Sheet1") -> bytes:
    bio = io.BytesIO()
    with pd.ExcelWriter(bio, engine="openpyxl") as writer:
        (df if df is not None else pd.DataFrame()).to_excel(writer, index=False, sheet_name=sheet_name[:31] or "Sheet1")
    return bio.getvalue()


def _to_csv_bytes(df: pd.DataFrame) -> bytes:
    """Much faster than Excel for browser downloads, especially after Review."""
    if df is None:
        df = pd.DataFrame()
    return df.to_csv(index=False, encoding="utf-8-sig").encode("utf-8-sig")


def _zip_paths(paths, zip_name: str) -> bytes:
    bio = io.BytesIO()
    with zipfile.ZipFile(bio, mode="w", compression=zipfile.ZIP_DEFLATED) as zf:
        for p in paths:
            if p and os.path.exists(p):
                zf.write(p, arcname=os.path.basename(p))
    bio.seek(0)
    return bio.getvalue()


def _build_prefix_and_tag(file_a_name: str, file_b_name: str):
    base_a = Path(file_a_name).stem if file_a_name else ""
    base_b = Path(file_b_name).stem if file_b_name else ""
    if base_a and base_b:
        return f"{base_a}_AND_{base_b}", "Both"
    if base_a:
        return base_a, "Aonly"
    return base_b or "streamlit_dedup", "Bonly"

