def _normalize_header_text(engine, text: str) -> str:
    if hasattr(engine, "normalize_col"):
        try:
            return engine.normalize_col(text)
        except Exception:
            pass
    return re.sub(r"[^a-z0-9]+", "", str(text or "").lower())



def _best_alias_score(engine, header_norm: str, aliases) -> int:
    best = 0
    for alias in aliases or []:
        alias_norm = _normalize_header_text(engine, alias)
        if not alias_norm or not header_norm:
            continue
        if header_norm == alias_norm:
            return 100
        if header_norm.startswith(alias_norm) or header_norm.endswith(alias_norm) or alias_norm.startswith(header_norm) or alias_norm.endswith(header_norm):
            best = max(best, 90)
        elif alias_norm in header_norm or header_norm in alias_norm:
            best = max(best, 80)
    return best



def _match_header_to_logic_key(engine, header: str):
    header_text = str(header or "").strip()
    header_lower = re.sub(r"\s+", " ", header_text.lower())
    header_norm = _normalize_header_text(engine, header)
    if not header_norm:
        return None, 0

    # Hard guards to stop common false matches.
    if any(token in header_lower for token in ["validity date", "expiry", "expiration", "expiry date", "expiration date", "exp date"]):
        return None, 0
    if header_lower in {"no", "no.", "number", "row no", "row no.", "row number"}:
        return None, 0

    # Prefer exact split-birth-part fields before fuzzy alias scoring.
    birth_part_rules = [
        ("birth_month", ["birth month", "birthmonth", "month of birth"]),
        ("birth_day", ["birth day", "birthday ", "day of birth", "birth dd", "birth_day"]),
        ("birth_year", ["birth year", "birthyear", "year of birth", "birth yyyy", "birth_year"]),
        ("birthdate", ["birthdate", "birth date", "date of birth", "dob", "mm/dd/yyyy", "m/d/yyyy", "mm-dd-yyyy", "m-d-yyyy"]),
    ]
    for logic_key, phrases in birth_part_rules:
        for phrase in phrases:
            phrase_norm = re.sub(r"\s+", " ", phrase.strip().lower())
            if header_lower == phrase_norm:
                return logic_key, 100

    best_key = None
    best_score = 0

    for logic_key, aliases in HEADER_EXTRA_ALIASES.items():
        score = _best_alias_score(engine, header_norm, aliases)
        if score > best_score:
            best_key = logic_key
            best_score = score

    patterns = getattr(engine, "COLUMN_PATTERNS", {}) or {}
    for engine_key, logic_key in ENGINE_TO_LOGIC_KEY.items():
        score = _best_alias_score(engine, header_norm, patterns.get(engine_key, []))
        if score > best_score:
            best_key = logic_key
            best_score = score

    return best_key, best_score



def _raw_finding_token(header: str) -> str:
    return RAW_FINDING_TOKEN_PREFIX + str(header or "").strip()


def _is_raw_finding_token(value) -> bool:
    return str(value or "").startswith(RAW_FINDING_TOKEN_PREFIX)


def _expand_logic_key(logic_key: str) -> list[str]:
    if _is_raw_finding_token(logic_key):
        return [logic_key]
    meta = HEADER_LOGIC_META.get(logic_key, {})
    expanded = meta.get("expands_to")
    if expanded:
        return list(expanded)
    return [logic_key] if logic_key else []



def _logic_choice_values() -> list[str]:
    return ["__ignore__", RAW_FINDING_LOGIC_KEY] + [k for k in LOGIC_MAPPING_ORDER if k in HEADER_LOGIC_META]



def _logic_choice_label(logic_key: str) -> str:
    if logic_key == "__ignore__":
        return "Keep Original / Not Used"
    if logic_key == RAW_FINDING_LOGIC_KEY:
        return "Keep Original / Finding Only"
    if _is_raw_finding_token(logic_key):
        return "Missing Data: " + str(logic_key)[len(RAW_FINDING_TOKEN_PREFIX):]
    meta = HEADER_LOGIC_META.get(logic_key, {})
    return meta.get("label", str(logic_key or "Keep Original"))


def _logic_choice_label_for_row(logic_key: str, detected_logic: str) -> str:
    if logic_key == "__ignore__":
        return "Keep Original / Not Used"
    if logic_key == RAW_FINDING_LOGIC_KEY:
        return "Keep Original / Finding Only"
    base_label = _logic_choice_label(logic_key)
    if detected_logic and logic_key == detected_logic:
        return f"Detect Header → {base_label}"
    return base_label



def _default_find_for_logic(logic_key: str) -> bool:
    keys = set(_expand_logic_key(logic_key))
    if logic_key:
        keys.add(logic_key)
    return any(k in DEFAULT_FINDING_FIELDS for k in keys)



def _default_dedup_for_logic(logic_key: str) -> bool:
    keys = set(_expand_logic_key(logic_key))
    if logic_key:
        keys.add(logic_key)
    return any(k in DEFAULT_DEDUPE_FIELDS for k in keys)



def _logic_note_for_row(logic_key: str, score: int) -> str:
    if logic_key == RAW_FINDING_LOGIC_KEY:
        return "Finding only: blank/N/A/Not Applicable in this original header will move the row to Finding. It is not used for Dedup."
    meta = HEADER_LOGIC_META.get(logic_key or "", {})
    if not logic_key or not meta:
        return "This column stays in the file, but it will not affect Finding or Dedup unless you map it."

    parts = []
    if meta.get("finding"):
        parts.append("Missing value can move the row to Finding.")
    else:
        parts.append("Not used to move rows to Finding.")

    if meta.get("dedup"):
        parts.append("Dedup checkbox uses fuzzy/similar matching for duplicate evidence.")
    else:
        parts.append("Not used to compare duplicate rows.")

    parts.append("If Not Applicable is checked, this column is ignored by the logic.")
    return " ".join(parts)



def _on_mapping_change(mapping_key: str, na_key: str, finding_key: str, dedup_key: str):
    _clear_previous_run_state()
    selected_logic = _coerce_removed_logic_key(st.session_state.get(mapping_key, "__ignore__"))
    st.session_state[mapping_key] = selected_logic
    if selected_logic == "__ignore__":
        st.session_state[na_key] = True
        st.session_state[finding_key] = False
        st.session_state[dedup_key] = False
        return
    if selected_logic == RAW_FINDING_LOGIC_KEY:
        st.session_state[na_key] = False
        st.session_state[finding_key] = True
        st.session_state[dedup_key] = False
        return

    meta = {"finding": True, "dedup": False} if selected_logic == RAW_FINDING_LOGIC_KEY else HEADER_LOGIC_META.get(selected_logic, {})
    st.session_state[na_key] = False
    st.session_state[finding_key] = _default_find_for_logic(selected_logic) if meta.get("finding") else False
    st.session_state[dedup_key] = _default_dedup_for_logic(selected_logic) if meta.get("dedup") else False



def _on_not_applicable_change(na_key: str, mapping_key: str, finding_key: str, dedup_key: str):
    _clear_previous_run_state()
    selected_logic = _coerce_removed_logic_key(st.session_state.get(mapping_key, "__ignore__"))
    st.session_state[mapping_key] = selected_logic
    if selected_logic == "__ignore__" or st.session_state.get(na_key, False):
        st.session_state[finding_key] = False
        st.session_state[dedup_key] = False
        st.session_state[na_key] = True
        return

    if selected_logic == RAW_FINDING_LOGIC_KEY:
        st.session_state[finding_key] = True
        st.session_state[dedup_key] = False
        return

    meta = HEADER_LOGIC_META.get(selected_logic, {})
    st.session_state[finding_key] = _default_find_for_logic(selected_logic) if meta.get("finding") else False
    st.session_state[dedup_key] = _default_dedup_for_logic(selected_logic) if meta.get("dedup") else False



def _on_logic_checkbox_change():
    _clear_previous_run_state()


def _build_header_row_state(row: dict, key_prefix: str) -> dict:
    mapping_key = f"{key_prefix}_mapping_{row['row_id']}"
    finding_key = f"{key_prefix}_finding_{row['row_id']}"
    dedup_key = f"{key_prefix}_dedup_{row['row_id']}"
    na_key = f"{key_prefix}_na_{row['row_id']}"

    if mapping_key not in st.session_state:
        initial_logic = _coerce_removed_logic_key(row.get("logic_key"))
        st.session_state[mapping_key] = initial_logic

    selected_logic = _coerce_removed_logic_key(st.session_state.get(mapping_key, "__ignore__"))
    if st.session_state.get(mapping_key) != selected_logic:
        st.session_state[mapping_key] = selected_logic
    meta = {"finding": True, "dedup": False} if selected_logic == RAW_FINDING_LOGIC_KEY else HEADER_LOGIC_META.get(selected_logic, {})

    if na_key not in st.session_state:
        st.session_state[na_key] = selected_logic == "__ignore__"

    if selected_logic == "__ignore__" or st.session_state.get(na_key, False):
        st.session_state[na_key] = True
        st.session_state[finding_key] = False
        st.session_state[dedup_key] = False
    else:
        if finding_key not in st.session_state:
            st.session_state[finding_key] = (True if selected_logic == RAW_FINDING_LOGIC_KEY else (_default_find_for_logic(selected_logic) if meta.get("finding") else False))
        if dedup_key not in st.session_state:
            st.session_state[dedup_key] = _default_dedup_for_logic(selected_logic) if meta.get("dedup") else False
        if not meta.get("finding"):
            st.session_state[finding_key] = False
        if not meta.get("dedup"):
            st.session_state[dedup_key] = False

    return {
        "mapping_key": mapping_key,
        "finding_key": finding_key,
        "dedup_key": dedup_key,
        "na_key": na_key,
    }



def _render_detected_header_controls(title: str, rows: list[dict], key_prefix: str, mode_label: str):
    st.markdown(f"**{title}**")
    if not rows:
        st.caption("No headers detected yet.")
        return []

    hdr1, hdr2, hdr3, hdr4, hdr5, hdr6 = st.columns([2.0, 1.7, 0.9, 0.9, 1.1, 4.2])
    hdr1.markdown("**Detected Header**")
    hdr2.markdown("**Use As**")
    hdr3.markdown("**Finding**")
    hdr4.markdown("**Dedup**")
    hdr5.markdown("**Not Applicable**")
    hdr6.markdown("**Meaning**")

    mapping_options = _logic_choice_values()
    resolved_rows = []

    for row in rows:
        state = _build_header_row_state(row, key_prefix)
        c1, c2, c3, c4, c5, c6 = st.columns([2.0, 1.7, 0.9, 0.9, 1.1, 4.2])
        c1.write(row["header"])

        current_logic = st.session_state.get(state["mapping_key"], row.get("logic_key") or "__ignore__")
        c2.selectbox(
            f"Use as {row['header']}",
            options=mapping_options,
            index=mapping_options.index(current_logic) if current_logic in mapping_options else 0,
            format_func=lambda value, detected=(row.get("detected_logic_key") or row.get("logic_key")): _logic_choice_label_for_row(value, detected),
            key=state["mapping_key"],
            label_visibility="collapsed",
            on_change=_on_mapping_change,
            args=(state["mapping_key"], state["na_key"], state["finding_key"], state["dedup_key"]),
        )

        selected_logic = st.session_state.get(state["mapping_key"], "__ignore__")
        meta = {"finding": True, "dedup": False} if selected_logic == RAW_FINDING_LOGIC_KEY else HEADER_LOGIC_META.get(selected_logic, {})
        na_disabled = selected_logic == "__ignore__"
        if na_disabled:
            st.session_state[state["na_key"]] = True
            st.session_state[state["finding_key"]] = False
            st.session_state[state["dedup_key"]] = False

        not_applicable = c5.checkbox(
            f"Not Applicable {row['header']}",
            key=state["na_key"],
            disabled=na_disabled,
            label_visibility="collapsed",
            on_change=_on_not_applicable_change,
            args=(state["na_key"], state["mapping_key"], state["finding_key"], state["dedup_key"]),
        )

        find_disabled = not_applicable or (not meta.get("finding"))
        dedup_disabled = not_applicable or (not meta.get("dedup"))

        find_checked = c3.checkbox(
            f"Finding {row['header']}",
            key=state["finding_key"],
            disabled=find_disabled,
            label_visibility="collapsed",
            on_change=_on_logic_checkbox_change,
        )
        dedup_checked = c4.checkbox(
            f"Dedup {row['header']}",
            key=state["dedup_key"],
            disabled=dedup_disabled,
            label_visibility="collapsed",
            on_change=_on_logic_checkbox_change,
        )

        if not_applicable:
            note = "This column is ignored by the logic. Data can stay, but it will not affect Clean, Finding, or Dedup."
        else:
            note = _logic_note_for_row(selected_logic, 100)
            if mode_label == "Generic" and selected_logic == "__ignore__":
                note = "Map this column first if you want it to affect the result."
        c6.caption(note)

        resolved_rows.append({
            "row_id": row["row_id"],
            "header": row["header"],
            "logic_key": None if selected_logic == "__ignore__" else selected_logic,
            "logic_label": _logic_choice_label(selected_logic),
            "finding_checked": bool(find_checked) and not bool(not_applicable),
            "dedup_checked": bool(dedup_checked) and not bool(not_applicable),
            "not_applicable": bool(not_applicable) or selected_logic == "__ignore__",
            "expanded_keys": ([_raw_finding_token(row["header"])] if selected_logic == RAW_FINDING_LOGIC_KEY else (_expand_logic_key(selected_logic) if selected_logic != "__ignore__" else [])),
        })

    return resolved_rows



def _control_rows_signature(control_rows: list[dict]):
    payload = []
    for row in control_rows or []:
        payload.append({
            "header": str(row.get("header", "")),
            "logic_key": row.get("logic_key") or "__ignore__",
            "finding": bool(row.get("finding_checked", False)),
            "dedupe": bool(row.get("dedup_checked", False)),
            "expanded_keys": row.get("expanded_keys", []),
            "not_applicable": bool(row.get("not_applicable", False)),
        })
    return json.dumps(payload, ensure_ascii=False, sort_keys=True)


def _collect_logic_selections(control_rows: list[dict]):
    finding_selected = set()
    dedupe_selected = set()
    for row in control_rows or []:
        if row.get("not_applicable"):
            continue
        if row.get("finding_checked"):
            finding_selected.update(row.get("expanded_keys", []))
        if row.get("dedup_checked"):
            dedupe_selected.update(row.get("expanded_keys", []))
    return finding_selected, dedupe_selected


def _enforce_optional_location_finding(finding_selected: set[str], *control_row_groups: list[dict]):
    selected = set(finding_selected or set())
    explicitly_checked = set()
    for rows in control_row_groups:
        for row in rows or []:
            if row.get("not_applicable"):
                continue
            if row.get("finding_checked"):
                explicitly_checked.update(
                    key for key in (row.get("expanded_keys") or [])
                    if key in OPTIONAL_FINDING_LOCATION_KEYS
                )
    for key in OPTIONAL_FINDING_LOCATION_KEYS:
        if key in selected and key not in explicitly_checked:
            selected.discard(key)
    return selected




def _collect_checked_header_finding_rules(control_rows: list[dict]) -> list[dict]:
    """Return original-header based missing-data rules from the visible header grid."""
    rules: list[dict] = []
    seen: set[str] = set()
    for row in control_rows or []:
        if row.get("not_applicable") or not row.get("finding_checked"):
            continue
        header = str(row.get("header", "")).strip()
        if not header:
            continue
        logic_key = row.get("logic_key") or ""
        rule_key = f"{header}||{logic_key}"
        if rule_key in seen:
            continue
        seen.add(rule_key)
        rules.append({
            "header": header,
            "logic_key": logic_key,
            "label": row.get("logic_label") or _logic_choice_label(logic_key) or header,
            "expanded_keys": list(row.get("expanded_keys") or []),
        })
    return rules


def _is_finding_missing_value(value) -> bool:
    if pd.isna(value):
        return True
    text = str(value).strip()
    if not text:
        return True
    compact = re.sub(r"[\s_\-./]+", "", text.lower())
    return compact in {
        "nan", "none", "null", "na", "n/a", "notapplicable", "notapply",
        "notavailable", "nodata", "missing", "blank", "empty", "unknown",
    }


def _finding_reason_column(*dfs) -> str:
    for df in dfs:
        if df is None or not hasattr(df, "columns"):
            continue
        for candidate in ("Lack_Reason", "FindingReason", "Finding_Reason", "Finding Reason", "Lack Reason", "Reason"):
            if candidate in df.columns:
                return candidate
    return "Lack_Reason"


def _join_reason(existing, new_reason: str) -> str:
    existing_text = "" if pd.isna(existing) else str(existing).strip()
    if not existing_text or existing_text.lower() in {"nan", "none"}:
        return new_reason
    parts = [p.strip() for p in re.split(r";|\|", existing_text) if p.strip()]
    if new_reason not in parts:
        parts.append(new_reason)
    return "; ".join(parts)


def _apply_checked_header_missing_rules_to_pair(clean_df: pd.DataFrame, lack_df: pd.DataFrame, rules: list[dict]):
    clean = _df_copy(clean_df)
    lack = _df_copy(lack_df)
    if clean is None or getattr(clean, "empty", True) or not rules:
        return clean, lack

    reason_bits = pd.Series("", index=clean.index, dtype="object")
    for rule in rules:
        header = str(rule.get("header", "")).strip()
        if not header or header not in clean.columns:
            continue
        missing_mask = clean[header].map(_is_finding_missing_value)
        if not bool(missing_mask.any()):
            continue
        reason_text = f"Missing Data: {header}"
        current = reason_bits.loc[missing_mask].astype(str)
        reason_bits.loc[missing_mask] = current.map(lambda x: _join_reason(x, reason_text))

    move_mask = reason_bits.astype(str).str.strip() != ""
    if not bool(move_mask.any()):
        return clean, lack

    reason_col = _finding_reason_column(lack, clean)
    moved = clean.loc[move_mask].copy()
    if reason_col not in moved.columns:
        moved[reason_col] = ""
    moved[reason_col] = [
        _join_reason(old, new)
        for old, new in zip(moved[reason_col].tolist(), reason_bits.loc[move_mask].tolist())
    ]

    remaining = clean.loc[~move_mask].copy()
    if lack is None or getattr(lack, "empty", True):
        fixed_lack = moved.reset_index(drop=True)
    else:
        fixed_lack = pd.concat([lack, moved], ignore_index=True, sort=False)
    return remaining.reset_index(drop=True), fixed_lack.reset_index(drop=True)




def _collect_checked_header_dedup_rules(control_rows: list[dict]) -> list[dict]:
    """Return original-header based fuzzy/similar dedup rules from the visible header grid."""
    rules: list[dict] = []
    seen: set[str] = set()
    for row in control_rows or []:
        if row.get("not_applicable") or not row.get("dedup_checked"):
            continue
        header = str(row.get("header", "")).strip()
        if not header:
            continue
        logic_key = row.get("logic_key") or ""
        if logic_key == RAW_FINDING_LOGIC_KEY or _is_raw_finding_token(logic_key):
            continue
        rule_key = f"{header}||{logic_key}"
        if rule_key in seen:
            continue
        seen.add(rule_key)
        rules.append({
            "header": header,
            "logic_key": logic_key,
            "label": row.get("logic_label") or _logic_choice_label(logic_key) or header,
            "expanded_keys": list(row.get("expanded_keys") or []),
        })
    return rules


def _dedup_checkbox_missing_value(value) -> bool:
    return _is_finding_missing_value(value)


def _dedup_checkbox_norm(value) -> str:
    if _dedup_checkbox_missing_value(value):
        return ""
    text = str(value).strip().casefold()
    # Keep letters/numbers only for stable matching. This treats punctuation, spaces, and hyphens as cosmetic.
    text = re.sub(r"[^0-9a-zñáéíóúü]+", "", text)
    return text


def _dedup_checkbox_text(value) -> str:
    if _dedup_checkbox_missing_value(value):
        return ""
    text = str(value).strip().casefold()
    text = re.sub(r"[^0-9a-zñáéíóúü]+", " ", text)
    return re.sub(r"\s+", " ", text).strip()


def _dedup_checkbox_similarity(a, b) -> float:
    na = _dedup_checkbox_text(a)
    nb = _dedup_checkbox_text(b)
    if not na or not nb:
        return 0.0
    ca = _dedup_checkbox_norm(na)
    cb = _dedup_checkbox_norm(nb)
    if ca and ca == cb:
        return 100.0
    # Basic token-sort style score without extra dependencies.
    ta = " ".join(sorted(na.split()))
    tb = " ".join(sorted(nb.split()))
    direct = SequenceMatcher(None, na, nb).ratio() * 100.0
    token = SequenceMatcher(None, ta, tb).ratio() * 100.0
    compact = SequenceMatcher(None, ca, cb).ratio() * 100.0 if ca and cb else 0.0
    return float(max(direct, token, compact))


def _dedup_checkbox_rule_weight(rule: dict) -> float:
    key = str(rule.get("logic_key") or "").lower()
    expanded = {str(k).lower() for k in (rule.get("expanded_keys") or [])}
    keys = expanded | {key}
    if keys & {"full_name", "first", "middle", "last", "suffix"}:
        return 2.4
    if keys & {"birthdate", "birth_year", "birth_month", "birth_day"}:
        return 1.8
    if keys & {"license_no", "contact_no"}:
        return 2.0
    if keys & {"province", "municipality", "barangay", "region", "lgu"}:
        return 0.8
    return 1.0


def _dedup_checkbox_is_identity_rule(rule: dict) -> bool:
    key = str(rule.get("logic_key") or "").lower()
    expanded = {str(k).lower() for k in (rule.get("expanded_keys") or [])}
    keys = expanded | {key}
    return bool(keys & {
        "full_name", "first", "middle", "last", "suffix",
        "birthdate", "birth_year", "birth_month", "birth_day",
        "license_no", "contact_no",
    })


def _dedup_checkbox_rule_threshold(rule: dict) -> float:
    key = str(rule.get("logic_key") or "").lower()
    expanded = {str(k).lower() for k in (rule.get("expanded_keys") or [])}
    keys = expanded | {key}
    if keys & {"birth_year", "birth_month", "birth_day", "sex", "age"}:
        return 100.0
    if keys & {"license_no", "contact_no"}:
        return 96.0
    if keys & {"region", "province", "municipality", "barangay", "lgu"}:
        return 82.0
    if keys & {"full_name", "first", "middle", "last", "suffix"}:
        return 74.0
    return 84.0


def _dedup_checkbox_block_keys(value) -> set[str]:
    text = _dedup_checkbox_text(value)
    norm = _dedup_checkbox_norm(value)
    if not norm:
        return set()
    no_vowel = re.sub(r"[aeiou]", "", norm)
    keys = {
        f"p:{norm[:6]}",
        f"s:{norm[-6:]}",
        f"l:{len(norm)}:{norm[:3]}",
    }
    if no_vowel:
        keys.add(f"v:{no_vowel[:6]}")
        keys.add(f"w:{no_vowel[-6:]}")
    for token in text.split():
        compact = _dedup_checkbox_norm(token)
        if len(compact) >= 3:
            keys.add(f"t:{compact[:4]}")
            keys.add(f"u:{compact[-4:]}")
    return {k for k in keys if len(k) > 3}


def _dedup_checkbox_existing_ids(df: pd.DataFrame) -> set[str]:
    if df is None or getattr(df, "empty", True):
        return set()
    id_cols = [c for c in ("_RowUID", "RowUID", "SourceRowNumber", "Source_Row_Number", "RowNumber", "Row_Number") if c in df.columns]
    if not id_cols:
        return set()
    out = set()
    for _, row in df.iterrows():
        parts = [str(row.get(c, "")) for c in id_cols]
        out.add("||".join(parts))
    return out


def _dedup_checkbox_row_id(row: pd.Series, fallback_idx) -> str:
    parts = []
    for col in ("_RowUID", "RowUID", "SourceRowNumber", "Source_Row_Number", "RowNumber", "Row_Number"):
        if col in row.index:
            val = row.get(col)
            if not _dedup_checkbox_missing_value(val):
                parts.append(str(val))
    return "||".join(parts) if parts else f"idx:{fallback_idx}"


def _dedup_checkbox_pair_score(row_a: pd.Series, row_b: pd.Series, rules: list[dict]):
    comparable = []
    identity_scores = []
    hard_fail = False
    for rule in rules or []:
        header = str(rule.get("header", "")).strip()
        if not header or header not in row_a.index or header not in row_b.index:
            continue
        va = row_a.get(header)
        vb = row_b.get(header)
        if _dedup_checkbox_missing_value(va) or _dedup_checkbox_missing_value(vb):
            continue
        score = _dedup_checkbox_similarity(va, vb)
        weight = _dedup_checkbox_rule_weight(rule)
        threshold = _dedup_checkbox_rule_threshold(rule)
        comparable.append((header, score, weight, threshold, rule))
        if _dedup_checkbox_is_identity_rule(rule):
            identity_scores.append(score)
        # Exact-like checked fields should not silently pass when both values exist but conflict.
        exact_keys = {str(k).lower() for k in (rule.get("expanded_keys") or [])} | {str(rule.get("logic_key") or "").lower()}
        if exact_keys & {"birth_year", "birth_month", "birth_day", "sex", "age"}:
            if score < 100.0:
                hard_fail = True

    if not comparable:
        return False, 0.0, []

    weighted_total = sum(score * weight for _, score, weight, _, _ in comparable)
    weight_total = sum(weight for _, _, weight, _, _ in comparable) or 1.0
    avg_score = weighted_total / weight_total
    min_score = min(score for _, score, _, _, _ in comparable)
    identity_best = max(identity_scores) if identity_scores else 0.0
    low_fields = [(h, score, threshold) for h, score, _, threshold, _ in comparable if score < threshold]

    # Safe acceptance rules:
    # 1 field selected: only full name/contact/license can stand alone.
    if len(comparable) == 1:
        h, score, _, _, rule = comparable[0]
        keyset = {str(k).lower() for k in (rule.get("expanded_keys") or [])} | {str(rule.get("logic_key") or "").lower()}
        if keyset & {"full_name"}:
            return score >= 92.0, score, [(h, score)]
        if keyset & {"contact_no", "license_no"}:
            return score >= 98.0, score, [(h, score)]
        return False, score, [(h, score)]

    if hard_fail:
        return False, avg_score, [(h, score) for h, score, _, _, _ in comparable]
    if not identity_scores:
        # Location/status columns alone can create massive false duplicates, so they are support only.
        return False, avg_score, [(h, score) for h, score, _, _, _ in comparable]
    if low_fields and avg_score < 90.0:
        return False, avg_score, [(h, score) for h, score, _, _, _ in comparable]

    accepted = (identity_best >= 88.0 and avg_score >= 86.0 and min_score >= 70.0)
    return accepted, avg_score, [(h, score) for h, score, _, _, _ in comparable]


def _append_dedup_checkbox_fuzzy_matches(clean_df: pd.DataFrame, dup_df: pd.DataFrame, rules: list[dict], scope_label: str):
    clean = _df_copy(clean_df)
    dup = _df_copy(dup_df)
    if clean is None or getattr(clean, "empty", True) or not rules:
        return clean, dup

    usable_rules = [r for r in rules if str(r.get("header", "")).strip() in clean.columns]
    if not usable_rules:
        return clean, dup

    identity_rules = [r for r in usable_rules if _dedup_checkbox_is_identity_rule(r)]
    if not identity_rules:
        return clean, dup

    # Build candidate pairs from selected identity-ish fields. Blocks keep the scan fast and avoid O(n²).
    blocks: dict[str, list[int]] = {}
    for idx, row in clean.iterrows():
        for rule in identity_rules:
            header = str(rule.get("header", "")).strip()
            for key in _dedup_checkbox_block_keys(row.get(header)):
                blocks.setdefault(f"{header}:{key}", []).append(idx)

    candidate_pairs = set()
    max_block_size = 350
    max_pairs = 350000
    for members in blocks.values():
        if len(members) < 2 or len(members) > max_block_size:
            continue
        members = sorted(set(members))
        for pos, i in enumerate(members[:-1]):
            for j in members[pos + 1:]:
                candidate_pairs.add((i, j))
                if len(candidate_pairs) >= max_pairs:
                    break
            if len(candidate_pairs) >= max_pairs:
                break
        if len(candidate_pairs) >= max_pairs:
            break

    if not candidate_pairs:
        return clean, dup

    matched_to = {}
    match_info = {}
    taken = set()
    for i, j in sorted(candidate_pairs):
        if j in taken:
            continue
        ok, score, field_scores = _dedup_checkbox_pair_score(clean.loc[i], clean.loc[j], usable_rules)
        if not ok:
            continue
        # Keep first encountered row as survivor/source; move later row to Dedup.
        source_idx, dup_idx = (i, j) if i < j else (j, i)
        if dup_idx in taken:
            continue
        matched_to[dup_idx] = source_idx
        match_info[dup_idx] = (score, field_scores)
        taken.add(dup_idx)

    if not matched_to:
        return clean, dup

    moved_rows = []
    for dup_idx, source_idx in matched_to.items():
        row = clean.loc[dup_idx].copy()
        score, field_scores = match_info.get(dup_idx, (0.0, []))
        source_row = clean.loc[source_idx]
        fields_text = ", ".join(f"{h} {round(s, 1)}%" for h, s in field_scores[:8])
        row["DedupType"] = row.get("DedupType", "FUZZ_DUPLICATE") or "FUZZ_DUPLICATE"
        row["Dedup_Label"] = row.get("Dedup_Label", "FUZZ DEDUP") or "FUZZ DEDUP"
        row["Match_Role"] = row.get("Match_Role", "MATCH DEDUP") or "MATCH DEDUP"
        row["Similarity_Score"] = round(float(score), 2)
        row["MatchPercentage"] = round(float(score), 2)
        row["ConflictReason"] = _join_reason(
            row.get("ConflictReason", ""),
            f"FUZZ_DUPLICATE by checked Dedup column(s): {fields_text}" if fields_text else "FUZZ_DUPLICATE by checked Dedup column(s)"
        )
        row["Dedup_Source_Row"] = _dedup_checkbox_row_id(source_row, source_idx)
        row["Dedup_Checkbox_Scope"] = scope_label
        moved_rows.append(row)

    moved = pd.DataFrame(moved_rows)
    remaining = clean.drop(index=list(matched_to.keys()), errors="ignore").reset_index(drop=True)

    if dup is None or getattr(dup, "empty", True):
        fixed_dup = moved.reset_index(drop=True)
    else:
        # Avoid appending the same source-row-id twice if a rerun used already-deduped result state.
        existing_ids = _dedup_checkbox_existing_ids(dup)
        if existing_ids:
            keep_mask = [(_dedup_checkbox_row_id(row, idx) not in existing_ids) for idx, row in moved.iterrows()]
            moved = moved.loc[keep_mask]
        fixed_dup = pd.concat([dup, moved], ignore_index=True, sort=False) if not moved.empty else dup
    return remaining, fixed_dup.reset_index(drop=True)


def _apply_checked_header_fuzzy_dedup_to_results(results: dict, rules_a: list[dict], rules_b: list[dict]) -> dict:
    out = dict(results or {})
    if not (rules_a or rules_b):
        return out
    out["clean_a"], out["dup_a"] = _append_dedup_checkbox_fuzzy_matches(out.get("clean_a"), out.get("dup_a"), rules_a, "File A")
    out["clean_b"], out["dup_b"] = _append_dedup_checkbox_fuzzy_matches(out.get("clean_b"), out.get("dup_b"), rules_b, "File B")
    combined_rules = _rules_for_combined_table(out.get("clean_ab"), rules_a, rules_b)
    out["clean_ab"], out["dup_ab"] = _append_dedup_checkbox_fuzzy_matches(out.get("clean_ab"), out.get("dup_ab"), combined_rules, "A+B")
    return out


def _apply_checked_header_fuzzy_dedup_to_engine(engine, rules_a: list[dict], rules_b: list[dict]):
    if engine is None or not (rules_a or rules_b):
        return
    results = {
        "clean_ab": getattr(engine, "result_clean_ab", pd.DataFrame()),
        "dup_ab": getattr(engine, "result_dup_ab", pd.DataFrame()),
        "clean_a": getattr(engine, "result_clean_a", pd.DataFrame()),
        "dup_a": getattr(engine, "result_dup_a", pd.DataFrame()),
        "clean_b": getattr(engine, "result_clean_b", pd.DataFrame()),
        "dup_b": getattr(engine, "result_dup_b", pd.DataFrame()),
    }
    fixed = _apply_checked_header_fuzzy_dedup_to_results(results, rules_a, rules_b)
    setattr(engine, "result_clean_ab", fixed.get("clean_ab", pd.DataFrame()))
    setattr(engine, "result_dup_ab", fixed.get("dup_ab", pd.DataFrame()))
    setattr(engine, "result_clean_a", fixed.get("clean_a", pd.DataFrame()))
    setattr(engine, "result_dup_a", fixed.get("dup_a", pd.DataFrame()))
    setattr(engine, "result_clean_b", fixed.get("clean_b", pd.DataFrame()))
    setattr(engine, "result_dup_b", fixed.get("dup_b", pd.DataFrame()))

def _find_source_column(df: pd.DataFrame) -> str | None:
    if df is None or getattr(df, "empty", True):
        return None
    priority = ["Source", "_Source", "SourceFile", "Source File", "FileSource", "File Source", "Table", "Origin"]
    for col in priority:
        if col in df.columns:
            return col
    for col in df.columns:
        text = str(col).lower().replace("_", " ")
        if "source" in text and "row" not in text:
            return col
    return None


def _rules_for_combined_table(clean_df: pd.DataFrame, rules_a: list[dict], rules_b: list[dict]) -> list[dict]:
    if not rules_b:
        return list(rules_a or [])
    if not rules_a:
        return list(rules_b or [])
    if _find_source_column(clean_df):
        by_key = {}
        for rule in list(rules_a or []) + list(rules_b or []):
            by_key[(rule.get("header"), rule.get("logic_key"))] = rule
        return list(by_key.values())
    headers_a = {r.get("header") for r in rules_a or []}
    headers_b = {r.get("header") for r in rules_b or []}
    common_headers = headers_a & headers_b
    by_key = {}
    for rule in list(rules_a or []) + list(rules_b or []):
        if rule.get("header") in common_headers:
            by_key[(rule.get("header"), rule.get("logic_key"))] = rule
    return list(by_key.values())


def _apply_checked_header_missing_finding_to_results(results: dict, rules_a: list[dict], rules_b: list[dict]) -> dict:
    out = dict(results or {})
    if not (rules_a or rules_b):
        return out
    out["clean_a"], out["lack_a"] = _apply_checked_header_missing_rules_to_pair(out.get("clean_a"), out.get("lack_a"), rules_a)
    out["clean_b"], out["lack_b"] = _apply_checked_header_missing_rules_to_pair(out.get("clean_b"), out.get("lack_b"), rules_b)
    combined_rules = _rules_for_combined_table(out.get("clean_ab"), rules_a, rules_b)
    out["clean_ab"], out["lack_ab"] = _apply_checked_header_missing_rules_to_pair(out.get("clean_ab"), out.get("lack_ab"), combined_rules)
    return out


def _remove_streamlit_internal_safe_placeholders_from_df(df):
    """Restore original user values after internal safe-fill bypasses old hard-coded Finding checks."""
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return df
    out = df.copy()

    def _norm_header(value):
        try:
            return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())
        except Exception:
            return ""

    marker_prefix = "__streamlit_original_value__::"
    marker_cols = [c for c in list(out.columns) if str(c).startswith(marker_prefix)]

    for marker_col in marker_cols:
        canonical = str(marker_col)[len(marker_prefix):]
        target_col = None
        canonical_norm = _norm_header(canonical)
        for col in list(out.columns):
            if col == marker_col:
                continue
            if _norm_header(col) == canonical_norm:
                target_col = col
                break
        try:
            if target_col is not None:
                out[target_col] = out[marker_col]
        except Exception:
            pass

    if marker_cols:
        try:
            out = out.drop(columns=marker_cols, errors="ignore")
        except Exception:
            pass

    # Fallback cleanup for outputs generated before marker columns existed.
    text_placeholders = {
        "Region Not Applicable",
        "Province Not Applicable",
        "City Not Applicable",
        "Barangay Not Applicable",
        "LGU Not Applicable",
    }
    try:
        for col in list(out.columns):
            if out[col].dtype == object:
                out[col] = out[col].map(lambda v: "" if str(v).strip() in text_placeholders else v)
    except Exception:
        pass

    try:
        for col in list(out.columns):
            if _norm_header(col) in {"contactno", "contactnumber", "mobilenumber", "phone", "phoneno"}:
                out[col] = out[col].map(lambda v: "" if str(v).strip() == "09000000000" else v)
    except Exception:
        pass

    return out


def _remove_streamlit_internal_safe_placeholders_results(results: dict) -> dict:
    out = dict(results or {})
    for key, value in list(out.items()):
        if isinstance(value, pd.DataFrame):
            out[key] = _remove_streamlit_internal_safe_placeholders_from_df(value)
    return out


def _apply_checked_header_missing_finding_to_engine(engine, rules_a: list[dict], rules_b: list[dict]):
    result_map = {
        "clean_ab": getattr(engine, "result_clean_ab", pd.DataFrame()),
        "lack_ab": getattr(engine, "result_lack_ab", getattr(engine, "result_no_detail_ab", pd.DataFrame())),
        "clean_a": getattr(engine, "result_clean_a", pd.DataFrame()),
        "lack_a": getattr(engine, "result_no_detail_a", pd.DataFrame()),
        "clean_b": getattr(engine, "result_clean_b", pd.DataFrame()),
        "lack_b": getattr(engine, "result_no_detail_b", pd.DataFrame()),
    }
    fixed = _apply_checked_header_missing_finding_to_results(result_map, rules_a, rules_b)
    fixed = _remove_streamlit_internal_safe_placeholders_results(fixed)
    setattr(engine, "result_clean_ab", fixed.get("clean_ab", pd.DataFrame()))
    setattr(engine, "result_lack_ab", fixed.get("lack_ab", pd.DataFrame()))
    if hasattr(engine, "result_no_detail_ab"):
        setattr(engine, "result_no_detail_ab", fixed.get("lack_ab", pd.DataFrame()))
    setattr(engine, "result_clean_a", fixed.get("clean_a", pd.DataFrame()))
    setattr(engine, "result_no_detail_a", fixed.get("lack_a", pd.DataFrame()))
    setattr(engine, "result_clean_b", fixed.get("clean_b", pd.DataFrame()))
    setattr(engine, "result_no_detail_b", fixed.get("lack_b", pd.DataFrame()))

def _unique_headers(headers: list[str]) -> list[str]:
    counts = {}
    result = []
    for header in headers:
        base = str(header or "Unnamed")
        counts[base] = counts.get(base, 0) + 1
        result.append(base if counts[base] == 1 else f"{base}__{counts[base]}")
    return result



def _split_full_name_simple(value):
    text = str(value or "").strip()
    if not text or text.lower() in {"nan", "none", "n/a", "na"}:
        return {"first": "", "middle": "", "last": "", "suffix": ""}

    clean = re.sub(r"\s+", " ", text.replace(";", " ").strip())
    if "," in clean:
        last_part, rest_part = [part.strip() for part in clean.split(",", 1)]
        tokens = rest_part.split()
        first = tokens[0] if tokens else ""
        suffix = ""
        if tokens and tokens[-1].lower().replace(".", "") in NAME_SPLIT_SUFFIXES:
            suffix = tokens[-1]
            tokens = tokens[:-1]
            first = tokens[0] if tokens else first
        middle = " ".join(tokens[1:]) if len(tokens) > 1 else ""
        return {"first": first, "middle": middle, "last": last_part, "suffix": suffix}

    tokens = clean.split()
    suffix = ""
    if tokens and tokens[-1].lower().replace(".", "") in NAME_SPLIT_SUFFIXES:
        suffix = tokens[-1]
        tokens = tokens[:-1]
    if len(tokens) == 1:
        return {"first": tokens[0], "middle": "", "last": "", "suffix": suffix}
    if len(tokens) == 2:
        return {"first": tokens[0], "middle": "", "last": tokens[1], "suffix": suffix}
    return {
        "first": tokens[0],
        "middle": " ".join(tokens[1:-1]),
        "last": tokens[-1],
        "suffix": suffix,
    }




def _apply_header_mapping_to_df(df: pd.DataFrame, control_rows: list[dict]):
    if df is None:
        return pd.DataFrame(), []

    out = df.copy()
    out.columns = [str(c) for c in out.columns]
    notices = []
    original_headers = [str(c) for c in out.columns]
    restore_meta = {
        "canonical_to_original": {},
        "helper_columns": [],
        "original_headers": list(original_headers),
        "strict_original_headers": True,
    }

    prepared_columns = {}
    used_targets = {}
    neutral_idx = 0

    row_lookup = {str(row.get("header", "")): row for row in (control_rows or [])}

    for header in original_headers:
        row = row_lookup.get(str(header), {})
        logic_key = row.get("logic_key")
        not_applicable = bool(row.get("not_applicable")) or not logic_key

        if not_applicable:
            neutral_idx += 1
            safe_name = f"RAWCOL_{neutral_idx:03d}"
            prepared_columns[str(header)] = safe_name
            restore_meta["canonical_to_original"][safe_name] = str(header)
            continue

        target = ENGINE_CANONICAL_HEADERS.get(logic_key)
        if not target:
            neutral_idx += 1
            safe_name = f"RAWCOL_{neutral_idx:03d}"
            prepared_columns[str(header)] = safe_name
            restore_meta["canonical_to_original"][safe_name] = str(header)
            continue

        used_targets[target] = used_targets.get(target, 0) + 1
        if used_targets[target] == 1:
            prepared_columns[str(header)] = target
            restore_meta["canonical_to_original"][str(target)] = str(header)
            visible_target = ENGINE_VISIBLE_OUTPUT_HEADERS.get(logic_key)
            if visible_target:
                restore_meta["canonical_to_original"][str(visible_target)] = str(header)
        else:
            neutral_idx += 1
            safe_name = f"RAWCOL_{neutral_idx:03d}"
            prepared_columns[str(header)] = safe_name
            restore_meta["canonical_to_original"][safe_name] = str(header)
            notices.append(f"More than one column was mapped to {target}. Only the first one is used for matching.")

    if prepared_columns:
        out = out.rename(columns=prepared_columns)
        out.columns = _unique_headers(list(out.columns))

    name_cols_present = any(col in out.columns for col in ["First Name", "Middle Name", "Last Name"])
    if (not name_cols_present) and ("Full Name" in out.columns):
        split_rows = out["Full Name"].apply(_split_full_name_simple)
        split_df = pd.DataFrame(split_rows.tolist(), index=out.index)
        mapping = {
            "first": "First Name",
            "middle": "Middle Name",
            "last": "Last Name",
            "suffix": "Extension Name",
        }
        for src_key, col_name in mapping.items():
            if col_name not in out.columns:
                out[col_name] = split_df[src_key]
        notices.append("Full Name was split into First Name, Middle Name, Last Name, and Extension Name for generic matching.")

    out, birth_notices = _normalize_birth_columns_for_matching(out)
    notices.extend(birth_notices)

    restore_meta["helper_columns"] = [
        str(col) for col in out.columns
        if str(col) not in set(original_headers) and str(col) not in set(restore_meta["canonical_to_original"].keys())
    ]
    out.attrs["_header_restore_meta"] = restore_meta
    return out, list(dict.fromkeys(notices))


def _blank_like(value) -> bool:
    if pd.isna(value):
        return True
    text = str(value or "").strip()
    return text == "" or text.lower() in {"nan", "none", "n/a", "na", "null"}


def _excel_serial_to_timestamp(value):
    try:
        num = float(value)
    except Exception:
        return None
    if not (1 <= num <= 600000):
        return None
    try:
        ts = pd.to_datetime(num, unit="D", origin="1899-12-30", errors="coerce")
    except Exception:
        return None
    if pd.isna(ts):
        return None
    return ts


def _parse_dateish_value(value):
    if value is None or pd.isna(value):
        return None
    if isinstance(value, pd.Timestamp):
        return None if pd.isna(value) else value
    if isinstance(value, (datetime, date)):
        return pd.Timestamp(value)

    serial_ts = _excel_serial_to_timestamp(value)
    if serial_ts is not None:
        return serial_ts

    text = str(value).strip()
    if not text or text.lower() in {"nan", "none", "n/a", "na", "null"}:
        return None

    explicit_formats = [
        ("%d-%b-%y", True), ("%d-%b-%Y", False), ("%d-%B-%y", True), ("%d-%B-%Y", False),
        ("%m/%d/%Y", False), ("%m/%d/%y", True), ("%m-%d-%Y", False), ("%m-%d-%y", True),
        ("%m/%d/%Y %H:%M:%S", False), ("%m/%d/%y %H:%M:%S", True),
    ]
    current_year = datetime.now().year
    for fmt, has_two_digit_year in explicit_formats:
        try:
            parsed_dt = datetime.strptime(text, fmt)
            if has_two_digit_year and parsed_dt.year > current_year:
                parsed_dt = parsed_dt.replace(year=parsed_dt.year - 100)
            ts = pd.Timestamp(parsed_dt)
        except Exception:
            ts = pd.NaT
        if not pd.isna(ts):
            return ts

    for dayfirst in (False, True):
        try:
            ts = pd.to_datetime(text, errors="coerce", dayfirst=dayfirst)
        except Exception:
            ts = pd.NaT
        if not pd.isna(ts):
            return ts
    return None



def _parse_birthdate_series_fast(series: pd.Series) -> pd.Series:
    """Vectorized parser for Birthdate columns; much faster than per-cell pd.to_datetime."""
    if series is None:
        return pd.Series(dtype="datetime64[ns]")
    raw = series.copy()
    text = raw.astype("string").str.strip()
    blank_mask = text.fillna("").str.lower().isin(["", "nan", "none", "n/a", "na", "null"])

    # Normal text/date parsing, first month-first then day-first as fallback.
    try:
        with warnings.catch_warnings():
            warnings.simplefilter("ignore")
            parsed = pd.to_datetime(raw, errors="coerce", dayfirst=False)
    except Exception:
        parsed = pd.Series(pd.NaT, index=series.index, dtype="datetime64[ns]")
    try:
        with warnings.catch_warnings():
            warnings.simplefilter("ignore")
            parsed_dayfirst = pd.to_datetime(raw, errors="coerce", dayfirst=True)
        parsed = parsed.fillna(parsed_dayfirst)
    except Exception:
        pass

    # Excel serial fallback for pure numeric dates.
    try:
        nums = pd.to_numeric(text.str.replace(r"[^0-9.]", "", regex=True), errors="coerce")
        serial_mask = nums.between(1, 600000)
        serial_ts = pd.to_datetime(nums.where(serial_mask), unit="D", origin="1899-12-30", errors="coerce")
        parsed = parsed.fillna(serial_ts)
    except Exception:
        pass

    parsed = parsed.mask(blank_mask, pd.NaT)
    return parsed

def _normalize_birth_year_value(value):
    if _blank_like(value):
        return ""
    if isinstance(value, (int, float)) and not pd.isna(value):
        year_num = int(value)
        if 1000 <= year_num <= 2200:
            return str(year_num)
    text_raw = str(value).strip()
    digits_only = re.sub(r"[^0-9]", "", text_raw)
    if digits_only.isdigit():
        year_num = int(digits_only)
        if 1000 <= year_num <= 2200 and not any(ch in text_raw for ch in ['/', '-', ':']):
            return str(year_num)
    ts = _parse_dateish_value(value)
    if ts is not None and not pd.isna(ts):
        return str(int(ts.year))
    if len(digits_only) >= 4:
        return digits_only[:4]
    return text_raw


def _normalize_birth_month_value(value):
    if _blank_like(value):
        return ""
    if isinstance(value, (int, float)) and not pd.isna(value):
        month_num = int(value)
        if 1 <= month_num <= 12:
            return str(month_num)
    text = str(value).strip()
    digits_direct = re.sub(r"[^0-9]", "", text)
    if digits_direct.isdigit() and not any(ch in text for ch in ['/', '-', ':']):
        month_num = int(digits_direct)
        if 1 <= month_num <= 12:
            return str(month_num)
    ts = _parse_dateish_value(value)
    if ts is not None and not pd.isna(ts):
        return str(int(ts.month))

    text_low = re.sub(r"[^a-z]", "", text.lower())
    month_map = {
        "jan": 1, "january": 1,
        "feb": 2, "february": 2,
        "mar": 3, "march": 3,
        "apr": 4, "april": 4,
        "may": 5,
        "jun": 6, "june": 6,
        "jul": 7, "july": 7,
        "aug": 8, "august": 8,
        "sep": 9, "sept": 9, "september": 9,
        "oct": 10, "october": 10,
        "nov": 11, "november": 11,
        "dec": 12, "december": 12,
    }
    if text_low in month_map:
        return str(month_map[text_low])

    digits = re.sub(r"[^0-9]", "", text)
    if digits:
        try:
            month_num = int(digits)
            if 1 <= month_num <= 12:
                return str(month_num)
        except Exception:
            pass
    return text


def _normalize_birth_day_value(value):
    if _blank_like(value):
        return ""
    if isinstance(value, (int, float)) and not pd.isna(value):
        day_num = int(value)
        if 1 <= day_num <= 31:
            return str(day_num)
    text = str(value).strip()
    digits = re.sub(r"[^0-9]", "", text)
    if digits.isdigit() and not any(ch in text for ch in ['/', '-', ':']):
        day_num = int(digits)
        if 1 <= day_num <= 31:
            return str(day_num)
    ts = _parse_dateish_value(value)
    if ts is not None and not pd.isna(ts):
        return str(int(ts.day))
    return text


def _normalize_birthdate_value(value):
    if _blank_like(value):
        return ""
    ts = _parse_dateish_value(value)
    if ts is None or pd.isna(ts):
        return str(value).strip()
    return f"{int(ts.month):02d}/{int(ts.day):02d}/{int(ts.year):04d}"


def _parsed_birth_part(ts, part: str) -> str:
    if ts is None or pd.isna(ts):
        return ""
    if part == "year":
        return str(int(ts.year))
    if part == "month":
        return str(int(ts.month))
    if part == "day":
        return str(int(ts.day))
    return ""


def _normalize_birth_columns_for_matching(df: pd.DataFrame):
    if df is None or df.empty:
        return df, []

    out = df.copy()
    notices = []
    birth_cols = {"Birthdate", "Birth Year", "Birth Month", "Birth Day"}
    present = birth_cols.intersection(set(out.columns))
    if not present:
        return out, notices

    if "Birthdate" in out.columns:
        parsed_birth = _parse_birthdate_series_fast(out["Birthdate"])
        valid_birth = parsed_birth.notna()
        normalized_birth = out["Birthdate"].astype("string").fillna("").str.strip()
        if valid_birth.any():
            normalized_birth.loc[valid_birth] = parsed_birth.loc[valid_birth].dt.strftime("%m/%d/%Y")
        out["Birthdate"] = normalized_birth.astype(str).replace({"<NA>": ""})
    else:
        parsed_birth = pd.Series(pd.NaT, index=out.index, dtype="datetime64[ns]")
        valid_birth = pd.Series(False, index=out.index)

    def _part_series(part: str) -> pd.Series:
        if parsed_birth is None or len(parsed_birth) == 0:
            return pd.Series([""] * len(out), index=out.index, dtype="object")
        valid = parsed_birth.notna()
        result = pd.Series([""] * len(out), index=out.index, dtype="object")
        if valid.any():
            if part == "year":
                result.loc[valid] = parsed_birth.loc[valid].dt.year.astype("Int64").astype(str)
            elif part == "month":
                result.loc[valid] = parsed_birth.loc[valid].dt.month.astype("Int64").astype(str)
            elif part == "day":
                result.loc[valid] = parsed_birth.loc[valid].dt.day.astype("Int64").astype(str)
        return result.replace({"<NA>": ""})

    if "Birthdate" in out.columns and "Birth Year" not in out.columns:
        out["Birth Year"] = _part_series("year")
    if "Birthdate" in out.columns and "Birth Month" not in out.columns:
        out["Birth Month"] = _part_series("month")
    if "Birthdate" in out.columns and "Birth Day" not in out.columns:
        out["Birth Day"] = _part_series("day")

    if "Birth Year" in out.columns:
        normalized_year = out["Birth Year"].apply(_normalize_birth_year_value).astype(str)
        if "Birthdate" in out.columns:
            normalized_year = normalized_year.where(~normalized_year.eq(""), _part_series("year"))
        out["Birth Year"] = normalized_year

    if "Birth Month" in out.columns:
        normalized_month = out["Birth Month"].apply(_normalize_birth_month_value).astype(str)
        if "Birthdate" in out.columns:
            normalized_month = normalized_month.where(~normalized_month.eq(""), _part_series("month"))
        out["Birth Month"] = normalized_month

    if "Birth Day" in out.columns:
        normalized_day = out["Birth Day"].apply(_normalize_birth_day_value).astype(str)
        if "Birthdate" in out.columns:
            normalized_day = normalized_day.where(~normalized_day.eq(""), _part_series("day"))
        out["Birth Day"] = normalized_day

    if present:
        notices.append("Birthdate columns were cleaned before matching so mixed date formats do not break dedup logic.")

    return out, notices

def _safe_source_row_count(path: str, sheet_name: str, header_row: int) -> int:
    """
    Fast row counter for large files. Avoids pd.read_excel(full workbook),
    which can freeze Review on 500K–1M rows just to display counts.
    """
    if not path or not sheet_name:
        return 0

    cache_key = (str(path), str(sheet_name), int(header_row or 0), "row_count_v2")
    cache = st.session_state.setdefault("_fast_row_count_cache", {})
    if cache_key in cache:
        return int(cache[cache_key] or 0)

    try:
        suffix = Path(str(path)).suffix.lower()
        if suffix in {".csv", ".txt"}:
            with open(path, "rb") as fh:
                line_count = sum(1 for _ in fh)
            count = max(0, line_count - int(header_row or 0) - 1)
            cache[cache_key] = count
            return count

        if suffix in {".xlsx", ".xlsm", ".xltx", ".xltm"}:
            try:
                from openpyxl import load_workbook
                wb = load_workbook(path, read_only=True, data_only=True)
                ws = wb[sheet_name] if sheet_name in wb.sheetnames else wb[wb.sheetnames[0]]
                count = max(0, int(ws.max_row or 0) - int(header_row or 0) - 1)
                wb.close()
                cache[cache_key] = count
                return count
            except Exception:
                pass

        # Last-resort fallback: read only first column instead of whole workbook.
        df = pd.read_excel(
            path,
            sheet_name=sheet_name,
            header=max(int(header_row or 0), 0),
            usecols=[0],
        )
        count = 0 if df is None else len(df)
        cache[cache_key] = count
        return count
    except Exception:
        return 0


def _prepare_run_file(
    uploaded_file,
    original_path: str,
    sheet_name: str,
    header_row: int,
    control_rows: list[dict],
    slot: str,
    max_rows: int | None = None,
):
    """
    Prepare the uploaded file for the embedded engine.

    Speed patch:
    - Run Preview / Review may pass max_rows, so it only processes a sample.
    - Build Export ZIP passes max_rows=None, so export remains full data.
    - Handoff is CSV because writing large XLSX files is much slower.
    """
    if not original_path or not sheet_name:
        return original_path, sheet_name, int(header_row or 0), []

    source = uploaded_file if uploaded_file is not None else original_path
    try:
        if hasattr(source, "seek"):
            source.seek(0)
    except Exception:
        pass

    read_kwargs = {
        "sheet_name": sheet_name,
        "header": max(int(header_row or 0), 0),
    }
    if max_rows is not None and int(max_rows) > 0:
        read_kwargs["nrows"] = int(max_rows)

    df = pd.read_excel(source, **read_kwargs)
    mapped_df, notices = _apply_header_mapping_to_df(df, control_rows)

    if max_rows is not None and int(max_rows) > 0:
        notices = list(notices or [])
        notices.append(
            f"Fast Review Mode is ON for Table {slot}: only the first {int(max_rows):,} rows were processed. "
            "Use Build Export ZIP for the full file."
        )

    st.session_state[f"header_restore_meta_{slot}"] = mapped_df.attrs.get("_header_restore_meta", {})

    prepared_dir = _get_session_dir() / "prepared"
    prepared_dir.mkdir(parents=True, exist_ok=True)
    original_stem = Path(_sanitize_filename(Path(original_path).name)).stem or f"file_{slot}"
    sample_tag = f"_review{int(max_rows)}" if max_rows is not None and int(max_rows) > 0 else ""
    prepared_name = f"{slot}_prepared{sample_tag}_{original_stem}.csv"
    prepared_path = prepared_dir / prepared_name

    mapped_df.to_csv(prepared_path, index=False, encoding="utf-8-sig")
    output_sheet = ""

    try:
        if hasattr(source, "seek"):
            source.seek(0)
    except Exception:
        pass

    return str(prepared_path), output_sheet, 0, notices




def _build_detected_header_rows(engine, headers: list[str], source_label: str):
    rows = []
    for idx, header in enumerate(headers or []):
        detected_logic_key, score = _match_header_to_logic_key(engine, header)
        logic_key = detected_logic_key
        meta = HEADER_LOGIC_META.get(logic_key or "", {})
        expanded_keys = _expand_logic_key(logic_key)
        rows.append({
            "row_id": f"{source_label}_{idx}",
            "source": source_label,
            "header": str(header),
            "logic_key": logic_key,
            "detected_logic_key": detected_logic_key,
            "logic_label": meta.get("label", "Keep Original / Not Used"),
            "finding_applicable": bool(meta.get("finding", False)),
            "dedup_applicable": bool(meta.get("dedup", False)),
            "expanded_keys": expanded_keys,
            "default_finding": _default_find_for_logic(logic_key),
            "default_dedup": _default_dedup_for_logic(logic_key),
            "note": _logic_note_for_row(logic_key, score),
        })
    return rows


def _format_logic_field_labels(field_keys: set[str], field_labels: dict[str, str], field_order: list[str]) -> str:
    ordered = [field_labels[k] for k in field_order if k in (field_keys or set()) and k in field_labels]
    extras = []
    for k in sorted(field_keys or set()):
        if k in field_labels:
            continue
        text = str(k)
        if _is_raw_finding_token(text):
            extras.append("Missing Data: " + text[len(RAW_FINDING_TOKEN_PREFIX):])
        else:
            extras.append(text)
    ordered.extend(extras)
    return ", ".join(ordered) if ordered else "None"


def _read_headers_from_upload(uploaded_file, sheet_name: str, header_row: int) -> list[str]:
    if uploaded_file is None or not sheet_name:
        return []
    try:
        uploaded_file.seek(0)
    except Exception:
        pass
    try:
        df = pd.read_excel(uploaded_file, sheet_name=sheet_name, header=max(int(header_row) - 1, 0), nrows=0)
        headers = [str(c) for c in df.columns]
    except Exception:
        headers = []
    finally:
        try:
            uploaded_file.seek(0)
        except Exception:
            pass
    return headers


def _render_checkbox_grid(title: str, field_order: list[str], field_labels: dict[str, str], defaults: set[str], key_prefix: str):
    st.markdown(f"**{title}**")
    cols = st.columns(3)
    selected = set()
    for idx, field_key in enumerate(field_order):
        label = field_labels.get(field_key, field_key)
        checked = cols[idx % 3].checkbox(label, value=(field_key in defaults), key=f"{key_prefix}_{field_key}")
        if checked:
            selected.add(field_key)
    return selected


def _apply_streamlit_field_overrides(engine, finding_fields: set[str], dedupe_fields: set[str]):
    finding_fields = set(finding_fields or set())
    dedupe_fields = set(dedupe_fields or set())
    expanded_finding_fields = set()
    for field_key in finding_fields:
        expanded = _expand_logic_key(field_key)
        if expanded:
            expanded_finding_fields.update(expanded)
        else:
            expanded_finding_fields.add(field_key)

    expanded_dedupe_fields = set()
    for field_key in dedupe_fields:
        expanded = _expand_logic_key(field_key)
        if expanded:
            expanded_dedupe_fields.update(expanded)
        else:
            expanded_dedupe_fields.add(field_key)

    required_vars = getattr(engine, "required_field_vars", {}) or {}
    for field_key, var in required_vars.items():
        try:
            var.set(field_key in expanded_finding_fields)
        except Exception:
            pass

    if not hasattr(engine, "_streamlit_original_birthdate_match_detail"):
        engine._streamlit_original_birthdate_match_detail = getattr(engine, "_birthdate_match_detail", None)
    if not hasattr(engine, "_streamlit_original_birth_candidate_block_keys"):
        engine._streamlit_original_birth_candidate_block_keys = getattr(engine, "_birth_candidate_block_keys", ())

    selected_name_fields = {k for k in expanded_dedupe_fields if k in {"first", "middle", "last", "suffix"}}
    if not selected_name_fields:
        selected_name_fields = {"first", "last"}

    selected_birth_parts = {k for k in expanded_dedupe_fields if k in {"birth_year", "birth_month", "birth_day"}}

    # Store the active checkbox logic on the engine so the internal cleaner does
    # not force unchecked / Not Applicable fields into Finding before dedup runs.
    try:
        engine._streamlit_finding_fields = set(expanded_finding_fields)
        engine._streamlit_dedupe_fields = set(expanded_dedupe_fields)
    except Exception:
        pass

    def _blankish(value):
        norm = engine.normalize_name(value)
        return "" if norm in {"", "na", "n/a", "none", "null", "unknown", "notapplicable", "notapp"} else norm

    def _name_fields_label():
        ordered = [DEDUPE_FIELD_LABELS[k] for k in DEDUPE_FIELD_ORDER if k in selected_name_fields]
        return ", ".join(ordered) if ordered else "Name"

    def _birth_fields_label():
        ordered = [DEDUPE_FIELD_LABELS[k] for k in DEDUPE_FIELD_ORDER if k in selected_birth_parts]
        return ", ".join(ordered) if ordered else "Birthdate"

    def _birth_candidate_block_keys_custom(norm_birth, include_birth=True):
        if not include_birth:
            return tuple()
        key = str(norm_birth or "").strip()
        if not key:
            return tuple()
        yy, mm, dd = engine._birth_parts_from_norm(key)
        if None in {yy, mm, dd}:
            return tuple()

        parts = set(selected_birth_parts)
        if parts == {"birth_year", "birth_month", "birth_day"}:
            return engine._streamlit_original_birth_candidate_block_keys(norm_birth, include_birth=include_birth)

        keys = []
        if parts == {"birth_year"}:
            keys.append(("BIRTH_Y", f"{yy:04d}"))
        elif parts == {"birth_month"}:
            keys.append(("BIRTH_M", f"{mm:02d}"))
        elif parts == {"birth_day"}:
            keys.append(("BIRTH_D", f"{dd:02d}"))
        else:
            if {"birth_year", "birth_month"}.issubset(parts):
                keys.append(("BIRTH_YM", f"{yy:04d}{mm:02d}"))
            if {"birth_year", "birth_day"}.issubset(parts):
                keys.append(("BIRTH_YD", f"{yy:04d}{dd:02d}"))
            if {"birth_month", "birth_day"}.issubset(parts):
                keys.append(("BIRTH_MD", f"{mm:02d}{dd:02d}"))
                md_lo, md_hi = min(mm, dd), max(mm, dd)
                keys.append(("BIRTH_MD_UNORDERED", f"{md_lo:02d}{md_hi:02d}"))
        return tuple(dict.fromkeys(keys))

    def _birthdate_match_detail_custom(norm_birth_1, norm_birth_2, include_birth=True):
        if not include_birth:
            return {"accepted": True, "exact": True, "score": 100.0, "reason": "Birthdate Check Disabled (Name-Only Mode)"}

        parts = set(selected_birth_parts)
        if parts == {"birth_year", "birth_month", "birth_day"}:
            return engine._streamlit_original_birthdate_match_detail(norm_birth_1, norm_birth_2, include_birth=include_birth)

        b1 = str(norm_birth_1 or "").strip()
        b2 = str(norm_birth_2 or "").strip()
        if not b1 or not b2:
            return {"accepted": False, "exact": False, "score": 0.0, "reason": f"{_birth_fields_label()} Missing On One Side"}

        y1, m1, d1 = engine._birth_parts_from_norm(b1)
        y2, m2, d2 = engine._birth_parts_from_norm(b2)
        if None in {y1, m1, d1, y2, m2, d2}:
            return {"accepted": False, "exact": False, "score": 0.0, "reason": f"{_birth_fields_label()} Not Comparable"}

        diffs = []
        if "birth_year" in parts and y1 != y2:
            diffs.append("Birth Year")
        if "birth_month" in parts and m1 != m2:
            diffs.append("Birth Month")
        if "birth_day" in parts and d1 != d2:
            diffs.append("Birth Day")
        if diffs:
            return {"accepted": False, "exact": False, "score": 0.0, "reason": "Different " + " / ".join(diffs)}
        return {"accepted": True, "exact": True, "score": 100.0, "reason": f"Same {_birth_fields_label()}"}

    def _cross_name_compatible(value_a, value_b, ph_a, ph_b, edit_tol, phonetic_min):
        if (
            engine.first_name_compatible(value_a, value_b, edit_tol, phonetic_min, ph_a=ph_a, ph_b=ph_b)
            or engine.field_compatible(value_a, value_b, edit_tol, phonetic_min, ph_a=ph_a, ph_b=ph_b)
        ):
            return True

        left = engine.normalize_name(value_a)
        right = engine.normalize_name(value_b)
        if not left or not right:
            return False
        if left == right or left in right or right in left:
            return True

        left_nv = re.sub(r"[aeiou]", "", left)
        right_nv = re.sub(r"[aeiou]", "", right)
        if left_nv and right_nv and (left_nv in right_nv or right_nv in left_nv):
            return True

        try:
            ratio_full = SequenceMatcher(None, left, right).ratio()
            ratio_nv = SequenceMatcher(None, left_nv, right_nv).ratio() if left_nv and right_nv else 0.0
            match = SequenceMatcher(None, left, right).find_longest_match(0, len(left), 0, len(right))
            common = int(getattr(match, "size", 0) or 0)
            shorter = max(1, min(len(left), len(right)))

            # Extra guard for real-world typo/transcription cases:
            # Carl/Karl, Cristina/Kristina, Abejero/Abijero.  These often fail
            # strict phonetic checks but should still be compared when birth and
            # the other selected name parts agree.
            left_tail_nv = re.sub(r"[aeiou]", "", left[1:]) if len(left) > 1 else left_nv
            right_tail_nv = re.sub(r"[aeiou]", "", right[1:]) if len(right) > 1 else right_nv
            same_tail_sound = bool(left_tail_nv and right_tail_nv and left_tail_nv == right_tail_nv and len(left_tail_nv) >= 2)

            if ratio_full >= 0.74 or ratio_nv >= 0.70 or same_tail_sound:
                return True
            if common >= 3 and (common / shorter) >= 0.55:
                return True
        except Exception:
            pass
        return False

    def _evaluate_pair(first1, middle1, last1, suffix1, first2, middle2, last2, suffix2,
                       firstph1, middleph1, lastph1, firstph2, middleph2, lastph2,
                       birth1, birth2, include_birth, threshold, edit_tol, phonetic_min):
        birth_detail = _birthdate_match_detail_custom(birth1, birth2, include_birth=include_birth)
        if include_birth and not birth_detail.get("accepted", False):
            return None

        first_norm_1 = engine.normalize_name(first1)
        first_norm_2 = engine.normalize_name(first2)
        first_canon_1 = engine.canonical_first_name(first1) or first_norm_1
        first_canon_2 = engine.canonical_first_name(first2) or first_norm_2
        last_norm_1 = engine.normalize_name(last1)
        last_norm_2 = engine.normalize_name(last2)
        middle_norm_1 = _blankish(middle1)
        middle_norm_2 = _blankish(middle2)
        suffix_norm_1 = engine.normalize_ext(suffix1)
        suffix_norm_2 = engine.normalize_ext(suffix2)

        exact_checks = []
        if "first" in selected_name_fields:
            exact_checks.append(bool(first_canon_1 and first_canon_2 and first_canon_1 == first_canon_2))
        if "middle" in selected_name_fields:
            exact_checks.append(middle_norm_1 == middle_norm_2)
        if "last" in selected_name_fields:
            exact_checks.append(bool(last_norm_1 and last_norm_2 and last_norm_1 == last_norm_2))
        if "suffix" in selected_name_fields:
            exact_checks.append(suffix_norm_1 == suffix_norm_2)
        exact_name_match = bool(exact_checks) and all(exact_checks)

        swap_possible = {"first", "last"}.issubset(selected_name_fields)
        swap_exact_checks = []
        if swap_possible:
            if "first" in selected_name_fields:
                swap_exact_checks.append(bool(first_norm_1 and last_norm_2 and first_norm_1 == last_norm_2))
            if "middle" in selected_name_fields:
                swap_exact_checks.append(middle_norm_1 == middle_norm_2)
            if "last" in selected_name_fields:
                swap_exact_checks.append(bool(last_norm_1 and first_norm_2 and last_norm_1 == first_norm_2))
            if "suffix" in selected_name_fields:
                swap_exact_checks.append(suffix_norm_1 == suffix_norm_2)
        swapped_exact_match = bool(swap_exact_checks) and all(swap_exact_checks)

        if exact_name_match:
            name_reason = f"Selected Name Fields Matched ({_name_fields_label()})"
            reason = f"{name_reason} And {birth_detail.get('reason', 'Birth Fields Matched')}"
            return {
                "score": 100.0 if birth_detail.get("exact", False) else min(98.5, max(93.0, float(birth_detail.get("score", 95.0)) + 1.0)),
                "type": "EXACT" if birth_detail.get("exact", False) else "CORE_NEAR_BIRTH",
                "reason": reason,
                "dedup_type": "TRUE_DUPLICATE" if birth_detail.get("exact", False) else "FUZZ_DUPLICATE",
                "confidence": "HIGH" if birth_detail.get("exact", False) else engine._dedup_confidence_label("FUZZ_DUPLICATE", exact_name=False, score=float(birth_detail.get("score", 95.0)), license_same=False),
                "conflict_reason": reason,
            }

        if swapped_exact_match:
            name_reason = f"Selected Name Fields Matched Under First/Last Swap ({_name_fields_label()})"
            reason = f"{name_reason} And {birth_detail.get('reason', 'Birth Fields Matched')}"
            return {
                "score": 100.0 if birth_detail.get("exact", False) else min(98.0, max(92.0, float(birth_detail.get("score", 95.0)) + 0.5)),
                "type": "EXACT" if birth_detail.get("exact", False) else "CORE_NEAR_BIRTH",
                "reason": reason,
                "dedup_type": "SWAP_TRUE_DUPLICATE" if birth_detail.get("exact", False) else "SWAP_FUZZ_DUPLICATE",
                "confidence": "HIGH" if birth_detail.get("exact", False) else engine._dedup_confidence_label("FUZZ_DUPLICATE", exact_name=False, score=float(birth_detail.get("score", 95.0)), license_same=False),
                "conflict_reason": reason,
            }

        first_ok = True if "first" not in selected_name_fields else _cross_name_compatible(first1, first2, firstph1, firstph2, edit_tol, phonetic_min)
        middle_ok = True if "middle" not in selected_name_fields else engine.middle_name_compatible(middle1, middle2, edit_tol, phonetic_min, mode=engine.MIDDLE_NAME_MODE, ph_a=middleph1, ph_b=middleph2)
        last_ok = True if "last" not in selected_name_fields else _cross_name_compatible(last1, last2, lastph1, lastph2, edit_tol, phonetic_min)
        suffix_ok = True if "suffix" not in selected_name_fields else (suffix_norm_1 == suffix_norm_2)

        normal_candidate = None
        if first_ok and middle_ok and last_ok and suffix_ok:
            profile = engine._dedup_name_profile(first1, middle1, last1, suffix1, first2, middle2, last2, suffix2)
            weights = {"first": 0.40, "middle": 0.20, "last": 0.35, "suffix": 0.05}
            field_scores = {
                "first": 100.0 if (first_canon_1 and first_canon_1 == first_canon_2) else float(profile.get("first_score", 0.0) or 0.0),
                "middle": 100.0 if (middle_norm_1 == middle_norm_2) else float(profile.get("middle_score", 0.0) or 0.0),
                "last": 100.0 if (last_norm_1 and last_norm_1 == last_norm_2) else float(profile.get("last_score", 0.0) or 0.0),
                "suffix": 100.0 if (suffix_norm_1 == suffix_norm_2) else 0.0,
            }
            total_weight = sum(weights[k] for k in selected_name_fields)
            name_score = sum(field_scores[k] * weights[k] for k in selected_name_fields) / total_weight if total_weight else 0.0
            score = (name_score * 0.85) + (float(birth_detail.get("score", 100.0)) * 0.15)
            if score >= max(82.0, float(threshold or 80.0)):
                raw_first_same = first_norm_1 == first_norm_2
                canon_first_same = first_canon_1 == first_canon_2
                mtype = "NICKNAME" if ("first" in selected_name_fields and not raw_first_same and canon_first_same) else "FUZZY"
                reason = f"Selected Name Fields Compatible ({_name_fields_label()}); {birth_detail.get('reason', 'Birth Fields Matched')}"
                normal_candidate = {
                    "score": score,
                    "type": mtype,
                    "reason": reason,
                    "dedup_type": "FUZZ_DUPLICATE",
                    "confidence": engine._dedup_confidence_label("FUZZ_DUPLICATE", exact_name=False, score=score, license_same=False),
                    "conflict_reason": reason,
                }

        swap_candidate = None
        if swap_possible:
            swap_first_ok = True if "first" not in selected_name_fields else _cross_name_compatible(first1, last2, firstph1, lastph2, edit_tol, phonetic_min)
            swap_middle_ok = True if "middle" not in selected_name_fields else engine.middle_name_compatible(middle1, middle2, edit_tol, phonetic_min, mode=engine.MIDDLE_NAME_MODE, ph_a=middleph1, ph_b=middleph2)
            swap_last_ok = True if "last" not in selected_name_fields else _cross_name_compatible(last1, first2, lastph1, firstph2, edit_tol, phonetic_min)
            swap_suffix_ok = True if "suffix" not in selected_name_fields else (suffix_norm_1 == suffix_norm_2)
            if swap_first_ok and swap_middle_ok and swap_last_ok and swap_suffix_ok:
                profile = engine._dedup_name_profile(first1, middle1, last1, suffix1, last2, middle2, first2, suffix2)
                weights = {"first": 0.40, "middle": 0.20, "last": 0.35, "suffix": 0.05}
                field_scores = {
                    "first": 100.0 if (first_norm_1 and last_norm_2 and first_norm_1 == last_norm_2) else float(profile.get("first_score", 0.0) or 0.0),
                    "middle": 100.0 if (middle_norm_1 == middle_norm_2) else float(profile.get("middle_score", 0.0) or 0.0),
                    "last": 100.0 if (last_norm_1 and first_norm_2 and last_norm_1 == first_norm_2) else float(profile.get("last_score", 0.0) or 0.0),
                    "suffix": 100.0 if (suffix_norm_1 == suffix_norm_2) else 0.0,
                }
                total_weight = sum(weights[k] for k in selected_name_fields)
                name_score = sum(field_scores[k] * weights[k] for k in selected_name_fields) / total_weight if total_weight else 0.0
                score = (name_score * 0.85) + (float(birth_detail.get("score", 100.0)) * 0.15)
                swap_fuzzy_min_score = max(70.0, min(float(threshold or 80.0), 82.0) - 7.0)
                if score >= swap_fuzzy_min_score:
                    reason = f"Selected Name Fields Compatible Under First/Last Swap ({_name_fields_label()}); {birth_detail.get('reason', 'Birth Fields Matched')}"
                    swap_candidate = {
                        "score": score,
                        "type": "FUZZY",
                        "reason": reason,
                        "dedup_type": "SWAP_FUZZ_DUPLICATE",
                        "confidence": engine._dedup_confidence_label("FUZZ_DUPLICATE", exact_name=False, score=score, license_same=False),
                        "conflict_reason": reason,
                    }

        if normal_candidate and swap_candidate:
            if swap_candidate["score"] > normal_candidate["score"] + 1.0:
                return swap_candidate
            return normal_candidate
        return normal_candidate or swap_candidate

    def _pair_match_detail_within_custom(idx1, idx2,
        first_list, first_canon_list, middle_list, last_list, suffix_list,
        identity_list, identity_ph_list,
        first_ph_list, middle_ph_list, last_ph_list, suffix_ph_list,
        birth_list, rowid_list, source_list, support_strict,
        include_birth, threshold, edit_tol, phonetic_min):
        return _evaluate_pair(
            engine._safe_list_value(first_list, idx1, ""), engine._safe_list_value(middle_list, idx1, ""), engine._safe_list_value(last_list, idx1, ""), engine._safe_list_value(suffix_list, idx1, ""),
            engine._safe_list_value(first_list, idx2, ""), engine._safe_list_value(middle_list, idx2, ""), engine._safe_list_value(last_list, idx2, ""), engine._safe_list_value(suffix_list, idx2, ""),
            engine._safe_list_value(first_ph_list, idx1, ""), engine._safe_list_value(middle_ph_list, idx1, ""), engine._safe_list_value(last_ph_list, idx1, ""),
            engine._safe_list_value(first_ph_list, idx2, ""), engine._safe_list_value(middle_ph_list, idx2, ""), engine._safe_list_value(last_ph_list, idx2, ""),
            engine._safe_list_value(birth_list, idx1, ""), engine._safe_list_value(birth_list, idx2, ""),
            include_birth, threshold, edit_tol, phonetic_min,
        )

    def _pair_match_detail_cross_custom(ia, ib,
        first_a, first_canon_a, middle_a, last_a, suffix_a,
        id_a, idph_a,
        firstph_a, middleph_a, lastph_a, suffixph_a,
        birth_a, rowid_a, source_a, support_strict_a,
        first_b, first_canon_b, middle_b, last_b, suffix_b,
        id_b, idph_b,
        firstph_b, middleph_b, lastph_b, suffixph_b,
        birth_b, rowid_b, source_b, support_strict_b,
        include_birth, threshold, edit_tol, phonetic_min):
        return _evaluate_pair(
            engine._safe_list_value(first_a, ia, ""), engine._safe_list_value(middle_a, ia, ""), engine._safe_list_value(last_a, ia, ""), engine._safe_list_value(suffix_a, ia, ""),
            engine._safe_list_value(first_b, ib, ""), engine._safe_list_value(middle_b, ib, ""), engine._safe_list_value(last_b, ib, ""), engine._safe_list_value(suffix_b, ib, ""),
            engine._safe_list_value(firstph_a, ia, ""), engine._safe_list_value(middleph_a, ia, ""), engine._safe_list_value(lastph_a, ia, ""),
            engine._safe_list_value(firstph_b, ib, ""), engine._safe_list_value(middleph_b, ib, ""), engine._safe_list_value(lastph_b, ib, ""),
            engine._safe_list_value(birth_a, ia, ""), engine._safe_list_value(birth_b, ib, ""),
            include_birth, threshold, edit_tol, phonetic_min,
        )

    def _dedup_type_rank_custom(dedup_type):
        mapping = {
            "TRUE_DUPLICATE": 400,
            "SWAP_TRUE_DUPLICATE": 300,
            "FUZZ_DUPLICATE": 200,
            "SWAP_FUZZ_DUPLICATE": 100,
        }
        return mapping.get(str(dedup_type or "").strip().upper(), 0)

    def _streamlit_include_birth_enabled(obj):
        try:
            return bool(getattr(obj, "_streamlit_include_birth", True))
        except Exception:
            return True

    def _streamlit_prepare_name_candidate_payload(obj, df, source_label="A"):
        try:
            total_rows = len(df)
        except Exception:
            total_rows = 0

        def _norm_header(value):
            try:
                return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())
            except Exception:
                return ""

        alias_sets = {
            "first": ["first_name", "firstname", "firstn", "first", "given_name", "givenname"],
            "middle": ["middle_name", "middlename", "middl", "middle", "mname"],
            "last": ["last_name", "lastname", "lastna", "last", "surname", "family_name", "familyname"],
            "suffix": ["extension_name", "extension", "exten", "ext_name", "ext", "suffix", "suffix_name", "jr", "sr"],
            "full": ["full_name", "fullname", "complete_name", "completename", "name"],
        }

        normalized_map = {}
        try:
            for col in list(df.columns):
                normalized_map[_norm_header(col)] = col
        except Exception:
            normalized_map = {}

        def _get_col(keys):
            for key in keys:
                col = normalized_map.get(_norm_header(key))
                if col is not None:
                    return col
            return None

        def _read_norm_list(keys):
            col = _get_col(keys)
            if col is None:
                return [""] * total_rows
            try:
                return [obj.normalize_name(v) for v in df[col].fillna("").tolist()]
            except Exception:
                try:
                    return [obj.normalize_name(v) for v in list(df[col])]
                except Exception:
                    return [""] * total_rows

        first = _read_norm_list(alias_sets["first"])
        middle = _read_norm_list(alias_sets["middle"])
        last = _read_norm_list(alias_sets["last"])
        suffix = _read_norm_list(alias_sets["suffix"])
        full = _read_norm_list(alias_sets["full"])

        if not any(full):
            full = [
                "|".join([part for part in [first[i], middle[i], last[i], suffix[i]] if part])
                for i in range(total_rows)
            ]

        def _soft_token(token):
            token = obj.normalize_name(token)
            if not token:
                return ""
            token = re.sub(r"[^a-z0-9]", "", token)
            no_vowel = re.sub(r"[aeiou]", "", token)
            tail_no_vowel = re.sub(r"[aeiou]", "", token[1:]) if len(token) > 1 else token
            return "|".join(filter(None, [no_vowel[:8], tail_no_vowel[:8], token[:1] + token[-2:]]))

        return {
            "first": first,
            "middle": middle,
            "last": last,
            "suffix": suffix,
            "full": full,
            "first_soft": [_soft_token(v) for v in first],
            "last_soft": [_soft_token(v) for v in last],
            "suffix_soft": [_soft_token(v) for v in suffix],
        }

    def _streamlit_name_block_keys(payload, idx):
        if not payload:
            return []

        def _get(arr):
            try:
                return engine.normalize_name(arr[idx])
            except Exception:
                return ""

        first = _get(payload.get("first", []))
        middle = _get(payload.get("middle", []))
        last = _get(payload.get("last", []))
        suffix = _get(payload.get("suffix", []))
        full = _get(payload.get("full", []))
        first_soft = _get(payload.get("first_soft", []))
        last_soft = _get(payload.get("last_soft", []))
        suffix_soft = _get(payload.get("suffix_soft", []))

        keys = set()
        if first and last:
            pair_sorted = tuple(sorted((first, last)))
            keys.add(("PAIR_EXACT",) + pair_sorted)
            keys.add(("PAIR_INIT",) + tuple(sorted(((first[:1] or ""), (last[:1] or "")))))
            keys.add(("PAIR2",) + tuple(sorted(((first[:2] or first[:1] or ""), (last[:2] or last[:1] or "")))))

            # Fuzzy/swap safety net for first-letter transcription variants:
            # Carl/Karl, Cris/Kris, Abejero/Abijero. Sorted tail keys also catch
            # swapped first/last with typo on either side.
            def _tail_nv_token(token):
                token = engine.normalize_name(token)
                if not token:
                    return ""
                tail = token[1:] if len(token) > 1 else token
                tail_nv = re.sub(r"[aeiou]", "", tail)
                return tail_nv[:8] if len(tail_nv) >= 2 else ""

            first_tail_nv = _tail_nv_token(first)
            last_tail_nv = _tail_nv_token(last)
            if first_tail_nv and last_tail_nv:
                keys.add(("PAIR_TAIL_NV",) + tuple(sorted((first_tail_nv, last_tail_nv))))
                keys.add(("PAIR_LAST_TAIL", last, first_tail_nv))
                keys.add(("PAIR_FIRST_TAIL", first, last_tail_nv))
            if middle:
                keys.add(("PAIR_MI",) + pair_sorted + (middle[:1] or "",))
            if suffix:
                keys.add(("PAIR_SX",) + pair_sorted + (suffix[:1] or "",))
            if first_soft and last_soft:
                keys.add(("PAIR_SOFT",) + tuple(sorted((first_soft, last_soft))))
                if middle:
                    keys.add(("PAIR_SOFT_MI",) + tuple(sorted((first_soft, last_soft))) + (middle[:1] or "",))
                if suffix_soft:
                    keys.add(("PAIR_SOFT_SX",) + tuple(sorted((first_soft, last_soft))) + (suffix_soft[:4] or "",))

            for token, soft in ((first, first_soft), (last, last_soft)):
                if token and len(token) >= 4:
                    keys.add(("TOKEN_EXACT", token))
                    keys.add(("TOKEN_EDGE", token[:1] + token[-2:]))
                if soft:
                    keys.add(("TOKEN_SOFT", soft))
                    if middle:
                        keys.add(("TOKEN_SOFT_MI", soft, middle[:1] or ""))
        elif full:
            keys.add(("FULL", full))
            keys.add(("FULL_INIT", full[:4]))
        return list(keys)

    if not hasattr(engine, "_streamlit_original_candidate_pairs_within"):
        engine._streamlit_original_candidate_pairs_within = engine._candidate_pairs_from_license_birth_within
    if not hasattr(engine, "_streamlit_original_candidate_pairs_cross"):
        engine._streamlit_original_candidate_pairs_cross = engine._candidate_pairs_from_license_birth_cross
    if not hasattr(engine, "_streamlit_original_dedup_within_df"):
        engine._streamlit_original_dedup_within_df = engine.dedup_within_df
    if not hasattr(engine, "_streamlit_original_dedup_cross_ab"):
        engine._streamlit_original_dedup_cross_ab = engine.dedup_cross_ab

    def _pairable_name_keys_for_candidate(payload, idx, include_birth_flag):
        """
        Candidate blocking must create possible pairs before the real scorer runs.
        The scorer still decides TRUE / FUZZ / SWAP / reject, so these keys are only a safe search net.
        """
        raw_keys = list(_streamlit_name_block_keys(payload, idx) or [])
        if not include_birth_flag:
            return raw_keys

        # When birth is enabled, keep name keys reasonably selective.
        # Birth validation will still reject non-matching birth parts after this.
        strong_prefixes = {
            "PAIR_EXACT", "PAIR_MI", "PAIR_SX",
            "PAIR_SOFT", "PAIR_SOFT_MI", "PAIR_SOFT_SX",
            "PAIR_TAIL_NV", "PAIR_LAST_TAIL", "PAIR_FIRST_TAIL",
            "FULL",
        }
        filtered = []
        for key in raw_keys:
            try:
                prefix = key[0]
            except Exception:
                prefix = ""
            if prefix in strong_prefixes:
                filtered.append(key)
        return filtered or raw_keys[:3]

    def _add_within_pairs_from_blocks(pairs, blocks, max_block_size=5000, hard_cap=None):
        used = 0
        skipped = 0
        cap = int(hard_cap or max_block_size or 5000)
        for members in blocks.values():
            uniq = sorted(set(members))
            if len(uniq) < 2:
                continue
            if len(uniq) > cap:
                skipped += 1
                continue
            used += 1
            for ix in range(len(uniq)):
                a = uniq[ix]
                for jx in range(ix + 1, len(uniq)):
                    b = uniq[jx]
                    if a != b:
                        pairs.add((a, b) if a < b else (b, a))
        return used, skipped

    def _add_cross_pairs_from_maps(pairs, map_a, map_b, max_block_size=5000, hard_cap=None):
        used = 0
        skipped = 0
        cap = int(hard_cap or max_block_size or 5000)
        for key, a_members in map_a.items():
            b_members = map_b.get(key)
            if not b_members:
                continue
            a_uniq = sorted(set(a_members))
            b_uniq = sorted(set(b_members))
            pair_count = len(a_uniq) * len(b_uniq)
            if pair_count > cap * cap:
                skipped += 1
                continue
            used += 1
            for ia in a_uniq:
                for ib in b_uniq:
                    pairs.add((ia, ib))
        return used, skipped

    def _birth_selected_keys_for_candidate(birth_value, include_birth_flag):
        if not include_birth_flag:
            return [("NO_BIRTH",)]
        try:
            keys = list(_birth_candidate_block_keys_custom(birth_value, include_birth=True) or [])
        except Exception:
            keys = []
        return keys

    def _candidate_pairs_from_license_birth_within_name_optional(license_list, birth_list, include_birth=True, max_block_size=5000):
        original = engine._streamlit_original_candidate_pairs_within(
            license_list, birth_list, include_birth=include_birth, max_block_size=max_block_size
        )
        try:
            base_pairs, used_blocks, skipped_blocks = original
        except Exception:
            base_pairs, used_blocks, skipped_blocks = original or [], 0, 0

        pairs = set(base_pairs or [])
        used_total = int(used_blocks or 0)
        skipped_total = int(skipped_blocks or 0)

        payload = getattr(engine, "_streamlit_current_name_payload_within", None)
        if not payload:
            return sorted(pairs), used_total, skipped_total

        n = len(payload.get("first", []) or payload.get("full", []) or [])
        effective_birth = bool(_streamlit_include_birth_enabled(engine))

        # 1) Add pure name blocks for swap and near-date cases.
        #    This fixes the common bug where SWAP logic exists but the pair is never compared.
        name_blocks = {}
        for i in range(int(n or 0)):
            for key in _pairable_name_keys_for_candidate(payload, i, effective_birth):
                name_blocks.setdefault(("NAME", key), []).append(i)
        name_cap = min(int(max_block_size or 5000), 750 if effective_birth else 1500)
        used, skipped = _add_within_pairs_from_blocks(pairs, name_blocks, max_block_size=max_block_size, hard_cap=name_cap)
        used_total += used
        skipped_total += skipped

        # 2) Add combined Name + selected Birth checkbox blocks.
        #    This makes "Birth Year only", "Year+Month", etc. actually affect candidate generation.
        if effective_birth and birth_list is not None:
            hybrid_blocks = {}
            for i in range(int(n or 0)):
                bkeys = _birth_selected_keys_for_candidate(engine._safe_list_value(birth_list, i, ""), True)
                if not bkeys:
                    continue
                nkeys = _streamlit_name_block_keys(payload, i)
                for bk in bkeys:
                    for nk in nkeys:
                        hybrid_blocks.setdefault(("NAME_BIRTH", bk, nk), []).append(i)
            used, skipped = _add_within_pairs_from_blocks(
                pairs, hybrid_blocks, max_block_size=max_block_size, hard_cap=min(int(max_block_size or 5000), 1000)
            )
            used_total += used
            skipped_total += skipped

        return sorted(pairs), used_total, skipped_total

    def _candidate_pairs_from_license_birth_cross_name_optional(license_a, birth_a, license_b, birth_b, include_birth=True, max_block_size=5000):
        original = engine._streamlit_original_candidate_pairs_cross(
            license_a, birth_a, license_b, birth_b, include_birth=include_birth, max_block_size=max_block_size
        )
        try:
            base_pairs, used_blocks, skipped_blocks = original
        except Exception:
            base_pairs, used_blocks, skipped_blocks = original or [], 0, 0

        pairs = set(base_pairs or [])
        used_total = int(used_blocks or 0)
        skipped_total = int(skipped_blocks or 0)

        payload_a = getattr(engine, "_streamlit_current_name_payload_a", None)
        payload_b = getattr(engine, "_streamlit_current_name_payload_b", None)
        if not payload_a or not payload_b:
            return sorted(pairs), used_total, skipped_total

        n_a = len(payload_a.get("first", []) or payload_a.get("full", []) or [])
        n_b = len(payload_b.get("first", []) or payload_b.get("full", []) or [])
        effective_birth = bool(_streamlit_include_birth_enabled(engine))

        # 1) Pure name blocks: catches cross-file swapped first/last and near-date duplicates.
        map_a = {}
        map_b = {}
        for ia in range(int(n_a or 0)):
            for key in _pairable_name_keys_for_candidate(payload_a, ia, effective_birth):
                map_a.setdefault(("NAME", key), []).append(ia)
        for ib in range(int(n_b or 0)):
            for key in _pairable_name_keys_for_candidate(payload_b, ib, effective_birth):
                map_b.setdefault(("NAME", key), []).append(ib)

        used, skipped = _add_cross_pairs_from_maps(
            pairs, map_a, map_b, max_block_size=max_block_size,
            hard_cap=min(int(max_block_size or 5000), 750 if effective_birth else 1500)
        )
        used_total += used
        skipped_total += skipped

        # 2) Hybrid selected-birth + name blocks: respects header checkbox combinations.
        if effective_birth and birth_a is not None and birth_b is not None:
            map_a = {}
            map_b = {}
            for ia in range(int(n_a or 0)):
                bkeys = _birth_selected_keys_for_candidate(engine._safe_list_value(birth_a, ia, ""), True)
                if not bkeys:
                    continue
                nkeys = _streamlit_name_block_keys(payload_a, ia)
                for bk in bkeys:
                    for nk in nkeys:
                        map_a.setdefault(("NAME_BIRTH", bk, nk), []).append(ia)
            for ib in range(int(n_b or 0)):
                bkeys = _birth_selected_keys_for_candidate(engine._safe_list_value(birth_b, ib, ""), True)
                if not bkeys:
                    continue
                nkeys = _streamlit_name_block_keys(payload_b, ib)
                for bk in bkeys:
                    for nk in nkeys:
                        map_b.setdefault(("NAME_BIRTH", bk, nk), []).append(ib)

            used, skipped = _add_cross_pairs_from_maps(
                pairs, map_a, map_b, max_block_size=max_block_size,
                hard_cap=min(int(max_block_size or 5000), 1000)
            )
            used_total += used
            skipped_total += skipped

        return sorted(pairs), used_total, skipped_total

    def _streamlit_ensure_dedup_headers(df):
        if df is None:
            return df
        work = df.copy()

        def _norm_header(value):
            try:
                return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())
            except Exception:
                return ""

        existing = {_norm_header(col) for col in list(work.columns)}
        required_aliases = {
            "first_name": ["first_name", "firstname", "firstn", "first", "given_name", "givenname"],
            "middle_name": ["middle_name", "middlename", "middle", "mname"],
            "last_name": ["last_name", "lastname", "last", "surname", "family_name", "familyname"],
            "extension_name": ["extension_name", "extension", "ext_name", "ext", "suffix", "suffix_name"],
            "full_name": ["full_name", "fullname", "complete_name", "completename", "name"],
            "month (mm)": ["monthmm", "month", "birthmonth", "mm"],
            "day (dd)": ["daydd", "day", "birthday", "dd"],
            "year (yyyy)": ["yearyyyy", "year", "birthyear", "yyyy"],
        }
        for canonical, aliases in required_aliases.items():
            alias_norms = {_norm_header(v) for v in aliases}
            if existing.isdisjoint(alias_norms) and _norm_header(canonical) not in existing:
                work[canonical] = ""
                existing.add(_norm_header(canonical))

        # Normalize Excel numeric birth parts before the embedded engine validates
        # them. Pandas/openpyxl commonly reads Year/Day as 1978.0 / 15.0, and the
        # original checker treats the decimal point as an invalid special character.
        def _find_existing_col(canonical_col):
            canonical_norm = _norm_header(canonical_col)
            for current_col in list(work.columns):
                if _norm_header(current_col) == canonical_norm:
                    return current_col
            return None

        def _clean_excel_int_text(value):
            try:
                if pd.isna(value):
                    return ""
            except Exception:
                pass
            raw = str(value).strip()
            if raw == "":
                return ""
            # 1978.0, 15.0, 02.0 -> 1978, 15, 2
            m = re.fullmatch(r"([0-9]+)\.0+", raw)
            if m:
                return m.group(1)
            try:
                f = float(raw.replace(",", ""))
                if f.is_integer():
                    return str(int(f))
            except Exception:
                pass
            return raw

        for _birth_col in ("month (mm)", "day (dd)", "year (yyyy)"):
            _col = _find_existing_col(_birth_col)
            if _col is not None:
                try:
                    work[_col] = work[_col].map(_clean_excel_int_text)
                except Exception:
                    pass

        # The embedded Tkinter engine has several hard-coded Lack/Finding checks
        # for location and birth headers. In Streamlit, the checkbox grid decides
        # whether a field is applicable. Without this guard, unchecked or
        # Not-Applicable fields can still push rows to Finding before duplicate
        # comparison runs, making dedup/swap look broken.
        finding_active = set(getattr(engine, "_streamlit_finding_fields", set()) or set())
        dedupe_active = set(getattr(engine, "_streamlit_dedupe_fields", set()) or set())

        def _is_blank_or_bad_series(series):
            if isinstance(series, pd.DataFrame):
                series = series.iloc[:, 0]
            ss = series.fillna("").astype(str).str.strip()
            ss_norm = ss.str.replace(r"[^A-Za-z0-9]", "", regex=True).str.lower()
            bad_norms = {"", "na", "n/a", "notapplicable", "notapp", "none", "null", "unknown", "missing", "nodata"}
            mask = (
                series.isna().fillna(False).astype(bool)
                | ss_norm.isin(bad_norms).fillna(False).astype(bool)
                | ss.str.lower().isin(bad_norms).fillna(False).astype(bool)
            )
            return mask.fillna(False).astype(bool)

        def _ensure_internal_safe_value(field_key, canonical_col, safe_value, protect_for_dedup=False):
            # If field is checked for Finding, preserve blanks so Finding can catch it.
            # If field is checked for Dedup, preserve real values so matching remains honest.
            if field_key in finding_active:
                return
            if protect_for_dedup and field_key in dedupe_active:
                return

            col = None
            canonical_norm = _norm_header(canonical_col)
            for current_col in list(work.columns):
                if _norm_header(current_col) == canonical_norm:
                    col = current_col
                    break

            # Safe-fill values are only for the embedded engine's hard-coded
            # completeness gate. Keep the user's original values in hidden helper
            # columns so preview/export can restore blanks instead of showing fake
            # values like "Region Not Applicable" or 01/01/1990.
            marker_col = f"__streamlit_original_value__::{canonical_col}"
            try:
                if marker_col not in work.columns:
                    if col is None:
                        work[marker_col] = ""
                    else:
                        work[marker_col] = work[col]
            except Exception:
                pass

            if col is None:
                work[canonical_col] = safe_value
                return
            try:
                mask = _is_blank_or_bad_series(work[col])
                if bool(mask.any()):
                    work.loc[mask, col] = safe_value
            except Exception:
                pass

        # Non-dedup support fields: only matter for Finding completeness.
        _ensure_internal_safe_value("region", "region", "Region Not Applicable")
        _ensure_internal_safe_value("province", "province", "Province Not Applicable")
        _ensure_internal_safe_value("municipality", "city/municipality", "City Not Applicable")
        _ensure_internal_safe_value("barangay", "barangay", "Barangay Not Applicable")
        _ensure_internal_safe_value("contact_no", "contact_no", "09000000000")
        _ensure_internal_safe_value("lgu", "lgu", "LGU Not Applicable")

        # Birth parts are both Finding and Dedup controls. Fill them only when
        # they are not selected for either logic; otherwise preserve the user's data.
        _ensure_internal_safe_value("birth_month", "month (mm)", 1, protect_for_dedup=True)
        _ensure_internal_safe_value("birth_day", "day (dd)", 1, protect_for_dedup=True)
        _ensure_internal_safe_value("birth_year", "year (yyyy)", 1990, protect_for_dedup=True)
        return work

    def _streamlit_effective_include_birth(include_birth_flag):
        try:
            return bool(selected_birth_parts)
        except Exception:
            return bool(include_birth_flag)

    def _dedup_within_df_name_optional(df, strict_level, include_birth, ui_progress_cb=None, source_label="A"):
        df_prepared = _streamlit_ensure_dedup_headers(df)
        effective_include_birth = _streamlit_effective_include_birth(include_birth)
        engine._streamlit_checkbox_rule_mode = "NAME_PLUS_BIRTH" if effective_include_birth else "NAME_ONLY"
        previous_include_birth = getattr(engine, "_streamlit_include_birth", bool(include_birth))
        engine._streamlit_include_birth = bool(effective_include_birth)
        engine._streamlit_current_name_payload_within = _streamlit_prepare_name_candidate_payload(engine, df_prepared, source_label=source_label)
        try:
            return engine._streamlit_original_dedup_within_df(df_prepared, strict_level, effective_include_birth, ui_progress_cb=ui_progress_cb, source_label=source_label)
        finally:
            engine._streamlit_current_name_payload_within = None
            engine._streamlit_include_birth = previous_include_birth

    def _dedup_cross_ab_name_optional(df_a, df_b, strict_level, include_birth, ui_progress_cb=None):
        df_a_prepared = _streamlit_ensure_dedup_headers(df_a)
        df_b_prepared = _streamlit_ensure_dedup_headers(df_b)
        effective_include_birth = _streamlit_effective_include_birth(include_birth)
        engine._streamlit_checkbox_rule_mode = "NAME_PLUS_BIRTH" if effective_include_birth else "NAME_ONLY"
        previous_include_birth = getattr(engine, "_streamlit_include_birth", bool(include_birth))
        engine._streamlit_include_birth = bool(effective_include_birth)
        engine._streamlit_current_name_payload_a = _streamlit_prepare_name_candidate_payload(engine, df_a_prepared, source_label="A")
        engine._streamlit_current_name_payload_b = _streamlit_prepare_name_candidate_payload(engine, df_b_prepared, source_label="B")
        try:
            return engine._streamlit_original_dedup_cross_ab(df_a_prepared, df_b_prepared, strict_level, effective_include_birth, ui_progress_cb=ui_progress_cb)
        finally:
            engine._streamlit_current_name_payload_a = None
            engine._streamlit_current_name_payload_b = None
            engine._streamlit_include_birth = previous_include_birth

    engine._birth_candidate_block_keys = _birth_candidate_block_keys_custom
    engine._birthdate_match_detail = _birthdate_match_detail_custom
    engine._pair_match_detail_within = _pair_match_detail_within_custom
    engine._pair_match_detail_cross = _pair_match_detail_cross_custom
    engine._dedup_type_rank = _dedup_type_rank_custom
    engine._candidate_pairs_from_license_birth_within = _candidate_pairs_from_license_birth_within_name_optional
    engine._candidate_pairs_from_license_birth_cross = _candidate_pairs_from_license_birth_cross_name_optional
    engine.dedup_within_df = _dedup_within_df_name_optional
    engine.dedup_cross_ab = _dedup_cross_ab_name_optional


def _patch_engine_for_streamlit(engine, progress_bar, status_box, metrics_box, message_box):
    def _raise_error(exc):
        raise RuntimeError(str(exc)) from exc

    def _ui_set_progress(percent):
        try:
            value = max(0.0, min(100.0, float(percent))) / 100.0
        except Exception:
            value = 0.0
        progress_bar.progress(value)

    def _ui_set_status(text="", metrics=""):
        if text:
            status_box.info(text)
        else:
            status_box.empty()
        if metrics:
            metrics_box.caption(metrics)
        else:
            metrics_box.empty()

    def _ui_message(kind, title, message):
        text = f"**{title}**\n\n{message}"
        if kind == "warning":
            message_box.warning(text)
        elif kind == "error":
            message_box.error(text)
        else:
            message_box.success(text)

    engine._run_on_ui_thread = lambda func, *args, wait=False, **kwargs: func(*args, **kwargs)
    engine._ui_set_progress = _ui_set_progress
    engine._ui_set_status = _ui_set_status
    engine._ui_message = _ui_message
    engine._ui_refresh_counts = lambda: None
    engine._ui_reset_report_all = lambda: getattr(engine, "reset_report", lambda: None)()
    engine.show_error = _raise_error



def _patch_engine_candidate_safety(engine):
    """Avoid explosive birth-year/month candidate blocks on large cross-match jobs.

    The original embedded engine also compares Year+Month and Year+Day candidate
    blocks. On 100k+ row sheets, those fuzzy-birth blocks can create millions of
    candidate pairs and make Streamlit look frozen. This safety patch keeps exact
    birthdate blocks (best for TRUE_DUPLICATE = name + birthdate) plus exact
    license blocks when available.
    """
    if getattr(engine, "_streamlit_candidate_safety_patched", False):
        return

    def _clean_key(v):
        key = str(v or "").strip()
        return "" if key.lower() in {"nan", "none", "null", "na", "n/a"} else key

    def _group_exact(values, tag):
        groups = {}
        if values is None:
            return groups
        for idx, val in enumerate(values):
            key = _clean_key(val)
            if key:
                groups.setdefault((tag, key), []).append(idx)
        return groups

    def _safe_pairs_within(license_list, birth_list, include_birth=True, max_block_size=2000):
        groups = {}
        if include_birth and birth_list is not None:
            groups.update(_group_exact(birth_list, "BIRTH_EXACT"))
        # License is optional but useful when present; keep it exact-only.
        if license_list is not None:
            for k, v in _group_exact(license_list, "LICENSE_EXACT").items():
                groups.setdefault(k, []).extend(v)

        pairs = set(); used_groups = 0; skipped_groups = 0
        for idxs in groups.values():
            idxs = sorted(set(idxs))
            if len(idxs) < 2:
                continue
            if len(idxs) > max_block_size:
                skipped_groups += 1
                continue
            used_groups += 1
            for a in range(len(idxs)):
                ia = idxs[a]
                for b in range(a + 1, len(idxs)):
                    ib = idxs[b]
                    pairs.add((ia, ib) if ia < ib else (ib, ia))
        return sorted(pairs), used_groups, skipped_groups

    def _safe_pairs_cross(license_a, birth_a, license_b, birth_b, include_birth=True, max_block_size=2000):
        groups_a = {}; groups_b = {}
        if include_birth and birth_a is not None and birth_b is not None:
            groups_a.update(_group_exact(birth_a, "BIRTH_EXACT"))
            groups_b.update(_group_exact(birth_b, "BIRTH_EXACT"))
        if license_a is not None and license_b is not None:
            for k, v in _group_exact(license_a, "LICENSE_EXACT").items():
                groups_a.setdefault(k, []).extend(v)
            for k, v in _group_exact(license_b, "LICENSE_EXACT").items():
                groups_b.setdefault(k, []).extend(v)

        pairs = set(); used_groups = 0; skipped_groups = 0
        for key in sorted(set(groups_a.keys()) & set(groups_b.keys())):
            idxs_a = sorted(set(groups_a.get(key, [])))
            idxs_b = sorted(set(groups_b.get(key, [])))
            if not idxs_a or not idxs_b:
                continue
            if len(idxs_a) > max_block_size or len(idxs_b) > max_block_size:
                skipped_groups += 1
                continue
            used_groups += 1
            for ia in idxs_a:
                for ib in idxs_b:
                    pairs.add((ia, ib))
        return sorted(pairs), used_groups, skipped_groups

    def _name_key(value):
        s = str(value or "").strip().lower()
        if not s:
            return ""
        if s.isalnum():
            return s
        return re.sub(r"[^a-z0-9]+", "", s)

    def _candidate_name_birth_within(first_list, last_list, first_ph_list, last_ph_list, birth_list, license_list, include_birth=True, max_block_size=80):
        groups = {}
        n = len(first_list or [])
        for i in range(n):
            birth = _clean_key((birth_list or [""] * n)[i]) if include_birth else "NO_BIRTH"
            if include_birth and not birth:
                continue
            first = _name_key((first_list or [""] * n)[i])
            last = _name_key((last_list or [""] * n)[i])
            fph = _clean_key((first_ph_list or [""] * n)[i])
            lph = _clean_key((last_ph_list or [""] * n)[i])
            keys = []
            if first and last:
                keys.append(("FULL_NAME_BIRTH", birth, last, first))
                keys.append(("PREFIX_NAME_BIRTH", birth, last[:4], first[:3]))
            if fph and lph:
                keys.append(("PH_NAME_BIRTH", birth, lph, fph))
            lic = _clean_key((license_list or [""] * n)[i])
            if lic:
                keys.append(("LICENSE", lic))
            for key in keys:
                groups.setdefault(key, []).append(i)
        pairs = set(); used = skipped = 0
        for idxs in groups.values():
            idxs = sorted(set(idxs))
            if len(idxs) < 2:
                continue
            if len(idxs) > max_block_size:
                skipped += 1
                continue
            used += 1
            for a in range(len(idxs)):
                ia = idxs[a]
                for b in range(a + 1, len(idxs)):
                    ib = idxs[b]
                    pairs.add((ia, ib) if ia < ib else (ib, ia))
        return sorted(pairs), used, skipped

    def _candidate_name_birth_cross(first_a, last_a, firstph_a, lastph_a, birth_a, license_a, first_b, last_b, firstph_b, lastph_b, birth_b, license_b, include_birth=True, max_block_size=80):
        def build_groups(first_list, last_list, first_ph_list, last_ph_list, birth_list, license_list):
            groups = {}
            n = len(first_list or [])
            for i in range(n):
                birth = _clean_key((birth_list or [""] * n)[i]) if include_birth else "NO_BIRTH"
                if include_birth and not birth:
                    continue
                first = _name_key((first_list or [""] * n)[i])
                last = _name_key((last_list or [""] * n)[i])
                fph = _clean_key((first_ph_list or [""] * n)[i])
                lph = _clean_key((last_ph_list or [""] * n)[i])
                keys = []
                if first and last:
                    keys.append(("FULL_NAME_BIRTH", birth, last, first))
                    keys.append(("PREFIX_NAME_BIRTH", birth, last[:4], first[:3]))
                if fph and lph:
                    keys.append(("PH_NAME_BIRTH", birth, lph, fph))
                lic = _clean_key((license_list or [""] * n)[i])
                if lic:
                    keys.append(("LICENSE", lic))
                for key in keys:
                    groups.setdefault(key, []).append(i)
            return groups
        groups_a = build_groups(first_a, last_a, firstph_a, lastph_a, birth_a, license_a)
        groups_b = build_groups(first_b, last_b, firstph_b, lastph_b, birth_b, license_b)
        pairs = set(); used = skipped = 0
        for key in sorted(set(groups_a.keys()) & set(groups_b.keys())):
            idxs_a = sorted(set(groups_a.get(key, [])))
            idxs_b = sorted(set(groups_b.get(key, [])))
            if not idxs_a or not idxs_b:
                continue
            if len(idxs_a) > max_block_size or len(idxs_b) > max_block_size or (len(idxs_a) * len(idxs_b) > 2000):
                skipped += 1
                continue
            used += 1
            for ia in idxs_a:
                for ib in idxs_b:
                    pairs.add((ia, ib))
        return sorted(pairs), used, skipped

    try:
        from rapidfuzz import fuzz as _fast_fuzz
    except Exception:
        _fast_fuzz = None

    def _ratio(a, b):
        a = _name_key(a); b = _name_key(b)
        if not a and not b:
            return 100.0
        if not a or not b:
            return 0.0
        if _fast_fuzz is not None:
            return float(_fast_fuzz.ratio(a, b))
        import difflib
        return float(difflib.SequenceMatcher(None, a, b).ratio() * 100.0)

    def _simple_pair_detail(first1, middle1, last1, suffix1, birth1, lic1, first2, middle2, last2, suffix2, birth2, lic2, threshold=80.0, include_birth=True):
        f1, m1, l1, s1 = _name_key(first1), _name_key(middle1), _name_key(last1), _name_key(suffix1)
        f2, m2, l2, s2 = _name_key(first2), _name_key(middle2), _name_key(last2), _name_key(suffix2)
        if not f1 or not l1 or not f2 or not l2:
            return None
        birth_same = (not include_birth) or (_clean_key(birth1) and _clean_key(birth1) == _clean_key(birth2))
        if not birth_same:
            # Keep the fast path strict for large cross-match jobs. Fuzzy-birth blocks are too expensive at this size.
            return None
        license_same = _clean_key(lic1) and _clean_key(lic1) == _clean_key(lic2)
        exact_core = (f1 == f2 and l1 == l2 and (not m1 or not m2 or m1 == m2) and (not s1 or not s2 or s1 == s2))
        if exact_core:
            reason = "Same core name + same birthdate"
            if license_same:
                reason += " + same license"
            return {"score": 100.0, "type": "EXACT", "reason": reason, "dedup_type": "TRUE_DUPLICATE", "confidence": "HIGH", "conflict_reason": reason}
        swap_exact = (f1 == l2 and l1 == f2)
        if swap_exact:
            reason = "First/last name swapped + same birthdate"
            return {"score": 98.0, "type": "SWAP_TRUE", "reason": reason, "dedup_type": "TRUE_DUPLICATE", "confidence": "HIGH", "conflict_reason": reason}
        name1 = " ".join([f1, m1, l1, s1]).strip()
        name2 = " ".join([f2, m2, l2, s2]).strip()
        score_full = _ratio(name1, name2)
        score_parts = (0.45 * _ratio(f1, f2)) + (0.45 * _ratio(l1, l2)) + (0.10 * _ratio(m1, m2))
        score = max(score_full, score_parts)
        swap_score = (0.50 * _ratio(f1, l2)) + (0.50 * _ratio(l1, f2))
        if swap_score >= max(82.0, threshold):
            reason = "Fuzzy first/last swap + same birthdate"
            return {"score": swap_score, "type": "SWAP_FUZZY", "reason": reason, "dedup_type": "FUZZ_DUPLICATE", "confidence": "REVIEW", "conflict_reason": reason}
        if score >= threshold:
            reason = "Fuzzy core name + same birthdate"
            return {"score": score, "type": "FUZZY", "reason": reason, "dedup_type": "FUZZ_DUPLICATE", "confidence": "REVIEW", "conflict_reason": reason}
        return None

    def _fast_build_identity_lists(df, include_birth=True, source_label="A"):
        n = len(df)
        def col(name):
            return df[name].astype("string").fillna("").astype(str) if name in df.columns else pd.Series([""] * n, index=df.index, dtype="object")
        first_s = col("First Name")
        middle_s = col("Middle Name")
        last_s = col("Last Name")
        suffix_s = col("Extension Name")
        if (first_s.str.strip().eq("").all() or last_s.str.strip().eq("").all()) and "Full Name" in df.columns:
            # Conservative fallback for single Full Name layouts: keep the full text in identity.
            full_s = col("Full Name")
            first_s = first_s.where(~first_s.str.strip().eq(""), full_s)
        raw_first_list = first_s.tolist(); raw_middle_list = middle_s.tolist(); raw_last_list = last_s.tolist(); raw_suffix_list = suffix_s.tolist()
        first_list = [_name_key(x) for x in raw_first_list]
        middle_list = [_name_key(x) for x in raw_middle_list]
        last_list = [_name_key(x) for x in raw_last_list]
        suffix_list = [_name_key(x) for x in raw_suffix_list]
        first_canon_list = first_list[:]  # keep fast; pair logic already receives normalized tokens
        identity_list = [(first_list[i] + " " + middle_list[i] + " " + last_list[i] + " " + suffix_list[i]).strip() for i in range(n)]
        # Phonetic lists are intentionally blank in the fast path; candidate blocking uses string prefixes.
        first_ph_list = [""] * n; middle_ph_list = [""] * n; last_ph_list = [""] * n; suffix_ph_list = [""] * n; identity_ph_list = [""] * n

        birth_list = [""] * n
        if include_birth:
            y = pd.to_numeric(col("Birth Year").str.replace(r"[^0-9]", "", regex=True), errors="coerce") if "Birth Year" in df.columns else pd.Series(pd.NA, index=df.index)
            m = pd.to_numeric(col("Birth Month").str.replace(r"[^0-9]", "", regex=True), errors="coerce") if "Birth Month" in df.columns else pd.Series(pd.NA, index=df.index)
            d = pd.to_numeric(col("Birth Day").str.replace(r"[^0-9]", "", regex=True), errors="coerce") if "Birth Day" in df.columns else pd.Series(pd.NA, index=df.index)
            valid = y.between(1800, 2200) & m.between(1, 12) & d.between(1, 31)
            if valid.any():
                birth_series = pd.Series([""] * n, index=df.index, dtype="object")
                yy = y.where(valid).astype("Int64").astype(str).replace("<NA>", "")
                mm = m.where(valid).astype("Int64").astype(str).str.zfill(2).replace("<NA>", "")
                dd = d.where(valid).astype("Int64").astype(str).str.zfill(2).replace("<NA>", "")
                birth_series.loc[valid] = yy.loc[valid] + "-" + mm.loc[valid] + "-" + dd.loc[valid]
                birth_list = birth_series.tolist()
            if (not any(birth_list)) and "Birthdate" in df.columns:
                parsed = _parse_birthdate_series_fast(df["Birthdate"])
                valid2 = parsed.notna()
                birth_series = pd.Series([""] * n, index=df.index, dtype="object")
                if valid2.any():
                    birth_series.loc[valid2] = parsed.loc[valid2].dt.strftime("%Y-%m-%d")
                birth_list = birth_series.tolist()

        license_list = col("License Number").tolist()
        plate_list = col("Plate Number").tolist()
        support_strict = [{} for _ in range(n)]

        # Fast Finding: only core name + birth completeness. Missing optional sheets/addresses are not mass-flagged.
        no_detail_mask = []
        lack_reason_list = []
        for i in range(n):
            reasons = []
            if not str(raw_first_list[i]).strip():
                reasons.append("Missing First Name")
            if not str(raw_last_list[i]).strip():
                reasons.append("Missing Last Name")
            if include_birth and not str(birth_list[i]).strip():
                reasons.append("Missing/Invalid Birthdate")
            no_detail_mask.append(bool(reasons))
            lack_reason_list.append("; ".join(reasons))

        return (
            first_list, first_canon_list, middle_list, last_list, suffix_list,
            identity_list, identity_ph_list,
            first_ph_list, middle_ph_list, last_ph_list, suffix_ph_list,
            birth_list, no_detail_mask, lack_reason_list,
            license_list, plate_list, support_strict,
        )

    def _fast_dedup_within_df(df, strict_level, include_birth, ui_progress_cb=None, source_label="A"):
        threshold, edit_tol, phonetic_min = engine.get_strictness_config(strict_level)
        (
            first_list, first_canon_list, middle_list, last_list, suffix_list,
            identity_list, identity_ph_list,
            first_ph_list, middle_ph_list, last_ph_list, suffix_ph_list,
            birth_list, no_detail_mask, lack_reason_list,
            license_list, plate_list, support_strict,
        ) = engine.build_identity_lists(df, include_birth, source_label)
        no_detail_indices_set = {i for i, v in enumerate(no_detail_mask) if v}
        candidate_pairs, _used_blocks, _skipped_blocks = _candidate_name_birth_within(
            first_list, last_list, first_ph_list, last_ph_list, birth_list, license_list, include_birth=include_birth
        )
        candidate_pairs = [(i, j) for (i, j) in candidate_pairs if i not in no_detail_indices_set and j not in no_detail_indices_set]

        start_time = time.time()
        dsu = engine._DSU(len(df))
        best_row_score = {}; best_row_type = {}; best_row_reason = {}; best_row_dedup_type = {}; best_row_confidence = {}; best_row_conflict_reason = {}
        total_pairs = len(candidate_pairs)
        for n, (idx1, idx2) in enumerate(candidate_pairs, start=1):
            if getattr(engine, "cancel_requested", False):
                raise RuntimeError("Cancelled")
            res = _simple_pair_detail(
                first_list[idx1], middle_list[idx1], last_list[idx1], suffix_list[idx1], birth_list[idx1], license_list[idx1],
                first_list[idx2], middle_list[idx2], last_list[idx2], suffix_list[idx2], birth_list[idx2], license_list[idx2],
                threshold=threshold, include_birth=include_birth
            )
            if res is not None:
                dsu.union(idx1, idx2)
                for idx in (idx1, idx2):
                    existing_type = best_row_dedup_type.get(idx, "")
                    should_update = (
                        idx not in best_row_score
                        or (engine._dedup_type_rank(res.get("dedup_type")) > engine._dedup_type_rank(existing_type))
                        or (engine._dedup_type_rank(res.get("dedup_type")) == engine._dedup_type_rank(existing_type) and res["score"] > best_row_score[idx])
                    )
                    if should_update:
                        best_row_score[idx] = res["score"]
                        best_row_type[idx] = res["type"]
                        best_row_reason[idx] = res.get("reason", "")
                        best_row_dedup_type[idx] = res.get("dedup_type", "TRUE_DUPLICATE")
                        best_row_confidence[idx] = res.get("confidence", "REVIEW")
                        best_row_conflict_reason[idx] = res.get("conflict_reason", "")
            if ui_progress_cb and total_pairs > 0 and (n % 200 == 0 or n == total_pairs):
                percent = (n / total_pairs) * 100
                elapsed = time.time() - start_time
                speed = n / elapsed if elapsed > 0 else 0
                remaining = (total_pairs - n) / speed if speed > 0 else 0
                ui_progress_cb(percent, n, total_pairs, speed, remaining)

        groups = {}
        for i in best_row_score.keys():
            if i in no_detail_indices_set:
                continue
            root_id = dsu.find(i)
            groups.setdefault(root_id, []).append(i)

        duplicate_indices = set(); ordered_dup_rows = []; match_group_no = 0
        sorted_groups = sorted([sorted(v) for v in groups.values() if len(v) >= 2], key=lambda g: min(g))
        for grp in sorted_groups:
            match_group_no += 1
            anchor = min(grp)
            members = [x for x in grp if x != anchor]
            members_sorted = sorted(members, key=lambda x: (-engine._dedup_type_rank(best_row_dedup_type.get(x, "")), engine._duplicate_tag_rank(best_row_type.get(x, "")), -best_row_score.get(x, 0.0), x))
            final_order = [anchor] + members_sorted
            for order_no, idx in enumerate(final_order, start=1):
                duplicate_indices.add(idx)
                row = df.iloc[idx].copy()
                row["Match_Group"] = match_group_no
                row["Group_Order"] = order_no
                row["Match_Role"] = "ANCHOR" if order_no == 1 else "DUPLICATE"
                row["Similarity_Score"] = engine._format_match_percentage(best_row_score.get(idx, 100.0 if order_no == 1 else 0.0), exact_name=(best_row_type.get(idx, "") == "EXACT"), birth_same=True)
                row["Match_Type"] = best_row_type.get(idx, "GROUP")
                row["DedupType"] = best_row_dedup_type.get(idx, "TRUE_DUPLICATE")
                row["Duplicate_Tag"] = row["Match_Type"]
                row["Duplicate_Reason"] = best_row_reason.get(idx, "Grouped duplicate match")
                row["Confidence"] = best_row_confidence.get(idx, "REVIEW")
                row["ConflictReason"] = best_row_conflict_reason.get(idx, row["Duplicate_Reason"])
                ordered_dup_rows.append(row)

        duplicates_df = pd.DataFrame(ordered_dup_rows).reset_index(drop=True) if ordered_dup_rows else df.iloc[0:0].copy()
        no_detail_indices = [i for i, v in enumerate(no_detail_mask) if v and i not in duplicate_indices]
        no_detail_df = df.loc[no_detail_indices].copy() if no_detail_indices else df.iloc[0:0].copy()
        if no_detail_indices:
            no_detail_df["Lack_Reason"] = [lack_reason_list[i] for i in no_detail_indices]
        elif "Lack_Reason" not in no_detail_df.columns:
            no_detail_df["Lack_Reason"] = ""
        to_drop = duplicate_indices | set(no_detail_indices)
        cleaned_df = df.drop(index=sorted(list(to_drop)), errors="ignore").copy()
        return cleaned_df, duplicates_df, no_detail_df

    def _fast_dedup_cross_ab(df_a, df_b, strict_level, include_birth, ui_progress_cb=None):
        threshold, edit_tol, phonetic_min = engine.get_strictness_config(strict_level)
        (
            first_a, first_canon_a, middle_a, last_a, suffix_a,
            id_a, idph_a,
            firstph_a, middleph_a, lastph_a, suffixph_a,
            birth_a, nodetail_a, lack_reason_a,
            license_a, plate_a, support_strict_a
        ) = engine.build_identity_lists(df_a, include_birth, "A")
        (
            first_b, first_canon_b, middle_b, last_b, suffix_b,
            id_b, idph_b,
            firstph_b, middleph_b, lastph_b, suffixph_b,
            birth_b, nodetail_b, lack_reason_b,
            license_b, plate_b, support_strict_b
        ) = engine.build_identity_lists(df_b, include_birth, "B")

        nodetail_a_set = {i for i, v in enumerate(nodetail_a) if v}
        nodetail_b_set = {i for i, v in enumerate(nodetail_b) if v}
        candidate_pairs, _used_blocks, _skipped_blocks = _candidate_name_birth_cross(
            first_a, last_a, firstph_a, lastph_a, birth_a, license_a,
            first_b, last_b, firstph_b, lastph_b, birth_b, license_b,
            include_birth=include_birth
        )

        def _add_birth_block_cross_candidates(existing_pairs, max_cross_product=5000):
            """Safety net: same-birth small blocks are allowed to compare all names.
            This catches Carl/Karl, typo, and swap cases that blocking keys can miss.
            Large birth blocks are skipped to avoid 500K+ file explosion.
            """
            pair_set = set((int(a), int(b)) for a, b in existing_pairs)
            if not include_birth:
                return list(pair_set)
            a_by_birth = {}
            b_by_birth = {}
            for i, b in enumerate(birth_a):
                if b and i not in nodetail_a_set:
                    a_by_birth.setdefault(str(b), []).append(i)
            for i, b in enumerate(birth_b):
                if b and i not in nodetail_b_set:
                    b_by_birth.setdefault(str(b), []).append(i)
            for b in set(a_by_birth).intersection(b_by_birth):
                la = a_by_birth.get(b, [])
                lb = b_by_birth.get(b, [])
                if not la or not lb:
                    continue
                if len(la) * len(lb) <= max_cross_product:
                    for ia in la:
                        for ib in lb:
                            pair_set.add((int(ia), int(ib)))
            return list(pair_set)

        candidate_pairs = _add_birth_block_cross_candidates(candidate_pairs)
        candidate_pairs = [(ia, ib) for (ia, ib) in candidate_pairs if ia not in nodetail_a_set and ib not in nodetail_b_set]

        start_time = time.time(); best_for_a = {}; best_for_b = {}; accepted_pairs = []
        total_pairs = len(candidate_pairs)
        for n, (ia, ib) in enumerate(candidate_pairs, start=1):
            if getattr(engine, "cancel_requested", False):
                raise RuntimeError("Cancelled")
            res = _simple_pair_detail(
                first_a[ia], middle_a[ia], last_a[ia], suffix_a[ia], birth_a[ia], license_a[ia],
                first_b[ib], middle_b[ib], last_b[ib], suffix_b[ib], birth_b[ib], license_b[ib],
                threshold=threshold, include_birth=include_birth
            )
            if res is not None:
                accepted_pairs.append((ia, ib, res["score"], res["type"], res.get("reason", ""), res.get("dedup_type", "TRUE_DUPLICATE"), res.get("confidence", "REVIEW"), res.get("conflict_reason", "")))
                old_a = best_for_a.get(ia); old_a_type = (old_a or {}).get("dedup_type", "")
                if old_a is None or (engine._dedup_type_rank(res.get("dedup_type")) > engine._dedup_type_rank(old_a_type)) or (engine._dedup_type_rank(res.get("dedup_type")) == engine._dedup_type_rank(old_a_type) and res["score"] > old_a["score"]):
                    best_for_a[ia] = {"ib": ib, "score": res["score"], "type": res["type"], "reason": res.get("reason", ""), "dedup_type": res.get("dedup_type", "TRUE_DUPLICATE"), "confidence": res.get("confidence", "REVIEW"), "conflict_reason": res.get("conflict_reason", "")}
                old_b = best_for_b.get(ib); old_b_type = (old_b or {}).get("dedup_type", "")
                if old_b is None or (engine._dedup_type_rank(res.get("dedup_type")) > engine._dedup_type_rank(old_b_type)) or (engine._dedup_type_rank(res.get("dedup_type")) == engine._dedup_type_rank(old_b_type) and res["score"] > old_b["score"]):
                    best_for_b[ib] = {"ia": ia, "score": res["score"], "type": res["type"], "reason": res.get("reason", ""), "dedup_type": res.get("dedup_type", "TRUE_DUPLICATE"), "confidence": res.get("confidence", "REVIEW"), "conflict_reason": res.get("conflict_reason", "")}
            if ui_progress_cb and total_pairs > 0 and (n % 200 == 0 or n == total_pairs):
                percent = 35.0 + ((n / total_pairs) * 65.0)
                elapsed = time.time() - start_time
                speed = n / elapsed if elapsed > 0 else 0
                remaining = (total_pairs - n) / speed if speed > 0 else 0
                ui_progress_cb(percent, n, total_pairs, speed, remaining)

        # Cross-file FAMILY grouping:
        # Old behavior selected only one A↔B pair per group. That could split the same person
        # across many rows (A exact, B exact, A fuzzy, A swap, etc.). This version unions every
        # accepted A↔B match into one connected family, then prints all members together.
        def _internal_dedup_type(dedup_type, mtype=None):
            m = str(mtype or "").strip().upper()
            if m == "EXACT":
                return "TRUE_DUPLICATE"
            if m == "FUZZY":
                return "FUZZ_DUPLICATE"
            if m == "SWAP_TRUE":
                return "SWAP_TRUE_DUPLICATE"
            if m == "SWAP_FUZZY":
                return "SWAP_FUZZ_DUPLICATE"
            return str(dedup_type or "TRUE_DUPLICATE").strip().upper()

        def _display_match_text(dedup_type, mtype=None):
            d = _internal_dedup_type(dedup_type, mtype)
            return {
                "TRUE_DUPLICATE": "true_duplicate",
                "FUZZ_DUPLICATE": "fuzzy_duplicate",
                "SWAP_TRUE_DUPLICATE": "swap_true_duplicate",
                "SWAP_FUZZ_DUPLICATE": "swap_fuzzy_duplicate",
            }.get(d, d.lower())

        def _family_match_order(dedup_type):
            # Display order requested by user: true, fuzzy, swap-true, swap-fuzzy.
            order_map = {
                "TRUE_DUPLICATE": 0,
                "FUZZ_DUPLICATE": 1,
                "SWAP_TRUE_DUPLICATE": 2,
                "SWAP_FUZZ_DUPLICATE": 3,
            }
            return order_map.get(str(dedup_type or "").strip().upper(), 9)

        def _family_quality_order(dedup_type):
            # Label-quality order before anchor-aware display correction.
            order_map = {
                "TRUE_DUPLICATE": 0,
                "SWAP_TRUE_DUPLICATE": 1,
                "FUZZ_DUPLICATE": 2,
                "SWAP_FUZZ_DUPLICATE": 3,
            }
            return order_map.get(str(dedup_type or "").strip().upper(), 9)

        def _norm_colname(value):
            return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())

        def _row_pick(row, aliases):
            wanted = {_norm_colname(x) for x in aliases}
            for colname in row.index:
                if _norm_colname(colname) in wanted:
                    val = row.get(colname, "")
                    if pd.notna(val) and str(val).strip():
                        return str(val).strip()
            return ""

        def _family_display_name(row):
            full = _row_pick(row, [
                "full_name", "full name", "fullname", "complete name", "complete_name",
                "completen name", "completename", "name of beneficiary", "beneficiary name",
                "client name", "name"
            ])
            if full:
                return full
            parts = [
                _row_pick(row, ["first_name", "firstname", "first name", "given name", "given_name"]),
                _row_pick(row, ["middle_name", "middlename", "middle name", "middle initial", "mi"]),
                _row_pick(row, ["last_name", "lastname", "last name", "surname", "family name"]),
                _row_pick(row, ["extension_name", "extensionname", "extension name", "ext_name", "ext name", "suffix", "suffix name"]),
            ]
            text = " ".join([p for p in parts if str(p).strip()])
            return text.strip()

        class _MiniDSU:
            def __init__(self):
                self.parent = {}

            def find(self, x):
                if x not in self.parent:
                    self.parent[x] = x
                while self.parent[x] != x:
                    self.parent[x] = self.parent[self.parent[x]]
                    x = self.parent[x]
                return x

            def union(self, a, b):
                ra, rb = self.find(a), self.find(b)
                if ra != rb:
                    self.parent[rb] = ra

        dsu = _MiniDSU()
        node_best = {}
        pair_info = {}

        def _update_node_best(node, score, mtype, reason, dedup_type, confidence, conflict_reason):
            dedup_type = _internal_dedup_type(dedup_type, mtype)
            old = node_best.get(node)
            old_rank = _family_quality_order(old.get("dedup_type")) if old else 99
            new_rank = _family_quality_order(dedup_type)
            if old is None or new_rank < old_rank or (new_rank == old_rank and float(score or 0) > float(old.get("score") or 0)):
                node_best[node] = {
                    "score": float(score or 0),
                    "type": mtype or "GROUP",
                    "reason": reason or "Cross-file duplicate match",
                    "dedup_type": _internal_dedup_type(dedup_type, mtype),
                    "confidence": confidence or "REVIEW",
                    "conflict_reason": conflict_reason or reason or "Cross-file duplicate match",
                }

        for ia, ib, score, mtype, reason, dedup_type, confidence, conflict_reason in accepted_pairs:
            node_a = ("A", int(ia))
            node_b = ("B", int(ib))
            dsu.union(node_a, node_b)
            info = {
                "score": float(score or 0),
                "type": mtype or "GROUP",
                "reason": reason or "Cross-file duplicate match",
                "dedup_type": _internal_dedup_type(dedup_type, mtype),
                "confidence": confidence or "REVIEW",
                "conflict_reason": conflict_reason or reason or "Cross-file duplicate match",
            }
            pair_info[(node_a, node_b)] = info
            _update_node_best(node_a, score, mtype, reason, dedup_type, confidence, conflict_reason)
            _update_node_best(node_b, score, mtype, reason, dedup_type, confidence, conflict_reason)

        # Also pull same-file variants into the same cross family.
        # Example: A has exact Carl + fuzzy Karl, B has exact Carl. Without this,
        # the cross sheet shows only A exact ↔ B exact and leaves A fuzzy outside the group.
        def _union_within_family(source_label, i, j, score, mtype, reason, dedup_type, confidence, conflict_reason):
            node_i = (source_label, int(i))
            node_j = (source_label, int(j))
            dsu.union(node_i, node_j)
            reason = reason or "Same-file variant connected to cross-match family"
            conflict_reason = conflict_reason or reason
            _update_node_best(node_i, score, mtype, reason, dedup_type, confidence, conflict_reason)
            _update_node_best(node_j, score, mtype, reason, dedup_type, confidence, conflict_reason)

        def _add_birth_block_within_candidates(existing_pairs, birth_list, nodetail_set, max_block_size=250):
            pair_set = set((int(a), int(b)) if int(a) < int(b) else (int(b), int(a)) for a, b in existing_pairs)
            if not include_birth:
                return list(pair_set)
            by_birth = {}
            for i, b in enumerate(birth_list):
                if b and i not in nodetail_set:
                    by_birth.setdefault(str(b), []).append(i)
            for items in by_birth.values():
                if 2 <= len(items) <= max_block_size:
                    for pos, ia in enumerate(items):
                        for ja in items[pos + 1:]:
                            pair_set.add((int(ia), int(ja)))
            return list(pair_set)

        within_pairs_a, _a_used, _a_skipped = _candidate_name_birth_within(
            first_a, last_a, firstph_a, lastph_a, birth_a, license_a, include_birth=include_birth
        )
        within_pairs_a = _add_birth_block_within_candidates(within_pairs_a, birth_a, nodetail_a_set)
        for ia, ja in within_pairs_a:
            ia = int(ia); ja = int(ja)
            if ia in nodetail_a_set or ja in nodetail_a_set:
                continue
            res = _simple_pair_detail(
                first_a[ia], middle_a[ia], last_a[ia], suffix_a[ia], birth_a[ia], license_a[ia],
                first_a[ja], middle_a[ja], last_a[ja], suffix_a[ja], birth_a[ja], license_a[ja],
                threshold=threshold, include_birth=include_birth
            )
            if res is not None:
                _union_within_family(
                    "A", ia, ja,
                    res.get("score", 0), res.get("type", "GROUP"), res.get("reason", ""),
                    res.get("dedup_type", "TRUE_DUPLICATE"), res.get("confidence", "REVIEW"),
                    res.get("conflict_reason", "")
                )

        within_pairs_b, _b_used, _b_skipped = _candidate_name_birth_within(
            first_b, last_b, firstph_b, lastph_b, birth_b, license_b, include_birth=include_birth
        )
        within_pairs_b = _add_birth_block_within_candidates(within_pairs_b, birth_b, nodetail_b_set)
        for ib, jb in within_pairs_b:
            ib = int(ib); jb = int(jb)
            if ib in nodetail_b_set or jb in nodetail_b_set:
                continue
            res = _simple_pair_detail(
                first_b[ib], middle_b[ib], last_b[ib], suffix_b[ib], birth_b[ib], license_b[ib],
                first_b[jb], middle_b[jb], last_b[jb], suffix_b[jb], birth_b[jb], license_b[jb],
                threshold=threshold, include_birth=include_birth
            )
            if res is not None:
                _union_within_family(
                    "B", ib, jb,
                    res.get("score", 0), res.get("type", "GROUP"), res.get("reason", ""),
                    res.get("dedup_type", "TRUE_DUPLICATE"), res.get("confidence", "REVIEW"),
                    res.get("conflict_reason", "")
                )

        components = {}
        for node in list(dsu.parent.keys()):
            components.setdefault(dsu.find(node), []).append(node)

        family_components = []
        for nodes in components.values():
            srcs = {n[0] for n in nodes}
            # Keep only real cross-file families, not accidental singletons.
            if len(nodes) >= 2 and "A" in srcs and "B" in srcs:
                family_components.append(nodes)

        def _node_first_last(node):
            src, idx = node
            idx = int(idx)
            if src == "A":
                return str(first_a[idx] or ""), str(last_a[idx] or "")
            return str(first_b[idx] or ""), str(last_b[idx] or "")

        def _is_swapped_against_anchor(node, anchor_node):
            cur_first, cur_last = _node_first_last(node)
            anchor_first, anchor_last = _node_first_last(anchor_node)
            if not cur_first or not cur_last or not anchor_first or not anchor_last:
                return False, 0.0, 0.0
            first_to_anchor_last = engine.similarity_score(cur_first, anchor_last)
            last_to_anchor_first = engine.similarity_score(cur_last, anchor_first)
            return (first_to_anchor_last >= 0.88 and last_to_anchor_first >= 0.74), first_to_anchor_last, last_to_anchor_first

        def _display_type_for_node(node, anchor_node, info):
            base_type = _internal_dedup_type(info.get("dedup_type", "TRUE_DUPLICATE"), info.get("type", ""))
            if node == anchor_node:
                return base_type
            swapped, s1, s2 = _is_swapped_against_anchor(node, anchor_node)
            if swapped:
                if s1 >= 0.97 and s2 >= 0.97:
                    return "SWAP_TRUE_DUPLICATE"
                return "SWAP_FUZZ_DUPLICATE"
            if base_type in {"SWAP_TRUE_DUPLICATE", "SWAP_FUZZ_DUPLICATE"}:
                # Sometimes broad blocking reports SWAP_FUZZY for a normal typo row.
                # When the row is not actually first/last-swapped against the anchor,
                # show it as fuzzy instead.
                return "FUZZ_DUPLICATE"
            return base_type

        def _node_sort_key(node):
            src, idx = node
            info = node_best.get(node, {})
            return (
                _family_match_order(info.get("dedup_type")),
                0 if src == "A" else 1,
                int(idx),
            )

        family_components = sorted(
            family_components,
            key=lambda nodes: min((0 if s == "A" else 1, int(i)) for s, i in nodes)
        )

        matched_a, matched_b = set(), set()
        ordered_rows = []
        match_group = 0

        for nodes in family_components:
            match_group += 1
            nodes_sorted = sorted(nodes, key=_node_sort_key)
            anchor_node = nodes_sorted[0]
            for order_no, node in enumerate(nodes_sorted, start=1):
                src_label, idx = node
                idx = int(idx)
                info = node_best.get(node, {
                    "score": 100.0 if order_no == 1 else 0.0,
                    "type": "GROUP",
                    "reason": "Cross-file grouped duplicate match",
                    "dedup_type": "TRUE_DUPLICATE",
                    "confidence": "REVIEW",
                    "conflict_reason": "Cross-file grouped duplicate match",
                })
                if src_label == "A":
                    matched_a.add(idx)
                    row = df_a.iloc[idx].copy()
                else:
                    matched_b.add(idx)
                    row = df_b.iloc[idx].copy()

                mtype = info.get("type", "GROUP")
                dedup_type = _internal_dedup_type(info.get("dedup_type", "TRUE_DUPLICATE"), mtype)
                display_dedup_type = _display_type_for_node(node, anchor_node, info)
                score = float(info.get("score") or 0.0)
                reason = info.get("reason", "Cross-file duplicate match")
                conflict = info.get("conflict_reason", reason)

                display_match = _display_match_text(display_dedup_type)
                display_match_type = mtype
                if display_dedup_type == "FUZZ_DUPLICATE" and str(mtype).upper().startswith("SWAP"):
                    display_match_type = "FUZZY"
                    reason = "Fuzzy core name + same birthdate"
                    conflict = reason
                elif display_dedup_type == "SWAP_TRUE_DUPLICATE":
                    display_match_type = "SWAP_TRUE"
                    reason = "First/last name swapped + same birthdate"
                    conflict = reason
                elif display_dedup_type == "SWAP_FUZZ_DUPLICATE":
                    display_match_type = "SWAP_FUZZY"
                    reason = "Fuzzy first/last swap + same birthdate"
                    conflict = reason

                row["Match"] = display_match
                row["Source"] = src_label
                row["Name"] = _family_display_name(row)
                row["_Source"] = src_label
                row["Match_Group"] = match_group
                row["Group_Order"] = order_no
                row["Match_Role"] = "ANCHOR" if order_no == 1 else "DUPLICATE"
                row["Match_Type"] = display_match_type
                row["DedupType"] = display_dedup_type
                row["Duplicate_Tag"] = mtype
                row["Duplicate_Reason"] = reason
                row["Reason"] = reason
                row["Similarity_Score"] = engine._format_match_percentage(score, exact_name=(mtype == "EXACT"), birth_same=True)
                row["Confidence"] = info.get("confidence", "REVIEW")
                row["ConflictReason"] = conflict
                ordered_rows.append(row)

        if ordered_rows:
            cross_dup_df = pd.DataFrame(ordered_rows).reset_index(drop=True)
            match_sort = {
                "true_duplicate": 0,
                "fuzzy_duplicate": 1,
                "swap_true_duplicate": 2,
                "swap_fuzzy_duplicate": 3,
            }
            cross_dup_df["_DisplaySort"] = cross_dup_df["Match"].map(match_sort).fillna(9).astype(int)
            cross_dup_df["_OldGroupOrder"] = cross_dup_df["Group_Order"].astype(int)
            cross_dup_df["_SourceSort"] = cross_dup_df["Source"].map({"A": 0, "B": 1}).fillna(9).astype(int)
            cross_dup_df = cross_dup_df.sort_values(["Match_Group", "_DisplaySort", "_SourceSort", "_OldGroupOrder"], kind="stable").reset_index(drop=True)
            cross_dup_df["Group_Order"] = cross_dup_df.groupby("Match_Group").cumcount() + 1
            cross_dup_df = cross_dup_df.drop(columns=["_DisplaySort", "_OldGroupOrder", "_SourceSort"], errors="ignore")
            front_cols = [c for c in ["Match_Group", "Group_Order", "Match", "Source", "Name", "Match_Role", "Similarity_Score", "ConflictReason"] if c in cross_dup_df.columns]
            other_cols = [c for c in cross_dup_df.columns if c not in front_cols]
            cross_dup_df = cross_dup_df[front_cols + other_cols]
        else:
            cross_dup_df = df_a.iloc[0:0].copy()

        clean_a = df_a.drop(index=sorted(list(matched_a)), errors="ignore").copy()
        clean_b = df_b.drop(index=sorted(list(matched_b)), errors="ignore").copy()
        return cross_dup_df, clean_a, clean_b

    try:
        engine._candidate_pairs_from_license_birth_within = _safe_pairs_within
        engine._candidate_pairs_from_license_birth_cross = _safe_pairs_cross
        engine.build_identity_lists = _fast_build_identity_lists
        engine.dedup_within_df = _fast_dedup_within_df
        engine.dedup_cross_ab = _fast_dedup_cross_ab
        engine._streamlit_candidate_safety_patched = True
    except Exception:
        pass

def _run_engine(
    engine,
    file_a_path,
    file_b_path,
    sheet_a,
    sheet_b,
    hdr_a,
    hdr_b,
    strict_level,
    include_birth,
    enable_min_age,
    min_age_limit,
    enable_max_age,
    max_age_limit,
):
    progress_box = st.progress(0.0)
    status_box = st.empty()
    metrics_box = st.empty()
    message_box = st.empty()
    _patch_engine_candidate_safety(engine)
    _patch_engine_for_streamlit(engine, progress_box, status_box, metrics_box, message_box)
    _apply_age_limit_overrides(engine, enable_min_age, min_age_limit, enable_max_age, max_age_limit)

    run_inputs = {
        "file_a": file_a_path or "",
        "file_b": file_b_path or "",
        "sheet_a": sheet_a or "",
        "sheet_b": sheet_b or "",
        "hdr_a": int(hdr_a or 0),
        "hdr_b": int(hdr_b or 0),
        "strict_level": int(strict_level or 80),
        "include_birth": bool(include_birth),
    }

    engine._streamlit_include_birth = bool(include_birth)
    engine.run_dedup_impl(export_files=False, run_inputs=run_inputs)

    results = {
        "clean_ab": _df_copy(_prefer_existing(getattr(engine, "result_clean_ab", None), getattr(engine, "_compute_clean_ab_df", lambda: None))),
        "dup_ab": _df_copy(_prefer_existing(getattr(engine, "result_dup_ab", None), getattr(engine, "_compute_dup_ab_df", lambda: None))),
        "lack_ab": _df_copy(_prefer_existing(getattr(engine, "result_lack_ab", None), getattr(engine, "_compute_lack_ab_df", lambda: None))),
        "clean_a": _df_copy(getattr(engine, "result_clean_a", None)),
        "dup_a": _df_copy(getattr(engine, "result_dup_a", None)),
        "lack_a": _df_copy(getattr(engine, "result_no_detail_a", None)),
        "clean_b": _df_copy(getattr(engine, "result_clean_b", None)),
        "dup_b": _df_copy(getattr(engine, "result_dup_b", None)),
        "lack_b": _df_copy(getattr(engine, "result_no_detail_b", None)),
        "cross_dup_ab": _df_copy(getattr(engine, "result_cross_dup_ab", None)),
        "cross_clean_a": _df_copy(getattr(engine, "result_cross_clean_a", None)),
        "cross_clean_b": _df_copy(getattr(engine, "result_cross_clean_b", None)),
    }
    results = _postprocess_age_reason_outputs(
        engine,
        results,
        enable_min_age,
        min_age_limit,
        enable_max_age,
        max_age_limit,
    )
    _promote_true_duplicate_survivors_for_export(engine)
    results = _postprocess_dedup_group_outputs(results)
    progress_box.progress(1.0)
    return results


def _display_result_block(label: str, df: pd.DataFrame, key_prefix: str):
    if df is None or getattr(df, "empty", True):
        st.caption(f"{label}: no data")
        return

    st.markdown(f"**{label}** — {len(df):,} rows × {len(df.columns):,} columns")

    # Browser rendering is one of the biggest slowdowns after a large Review.
    preview_limit = 1000
    shown_df = df.head(preview_limit) if len(df) > preview_limit else df
    if len(df) > preview_limit:
        st.caption(f"Browser preview limited to first {preview_limit:,} rows for speed.")

    st.dataframe(shown_df, use_container_width=True, height=420)

    # Do not eagerly generate large XLSX downloads on every rerun.
    # XLSX creation can feel like the Review button is frozen.
    safe_label = re.sub(r"[^A-Za-z0-9_-]+", "_", label)
    if len(df) <= 50000:
        st.download_button(
            f"Download {label} as Excel",
            data=_to_excel_bytes(df, sheet_name=label[:31]),
            file_name=f"{key_prefix}_{safe_label}.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            key=f"download_xlsx_{key_prefix}_{label}",
        )
    elif len(df) <= 200000:
        st.download_button(
            f"Download {label} as CSV",
            data=_to_csv_bytes(df),
            file_name=f"{key_prefix}_{safe_label}.csv",
            mime="text/csv",
            key=f"download_csv_{key_prefix}_{label}",
        )
        st.caption("CSV download is used for this large table because Excel generation is much slower.")
    else:
        st.warning(
            f"{label} is very large. To avoid browser freezing, table download is disabled here. "
            "Use **Build Export ZIP** for the full output."
        )




def _template_store_dir() -> Path:
    root = Path(__file__).resolve().parent / "_dedup_header_templates"
    root.mkdir(parents=True, exist_ok=True)
    return root



def _safe_template_name(name: str) -> str:
    clean = re.sub(r"[^A-Za-z0-9._-]+", "_", str(name or "last_used").strip())
    return clean or "last_used"



def _template_file_path(name: str) -> Path:
    return _template_store_dir() / f"{_safe_template_name(name)}.json"



def _build_template_rows_from_state(header_rows: list[dict], key_prefix: str) -> dict:
    payload = {}
    for row in header_rows or []:
        row_id = row["row_id"]
        mapping_key = f"{key_prefix}_mapping_{row_id}"
        finding_key = f"{key_prefix}_finding_{row_id}"
        dedup_key = f"{key_prefix}_dedup_{row_id}"
        na_key = f"{key_prefix}_na_{row_id}"
        logic_key = st.session_state.get(mapping_key, row.get("logic_key") or "__ignore__")
        payload[str(row["header"])] = {
            "logic_key": logic_key,
            "finding": bool(st.session_state.get(finding_key, row.get("default_finding", False))),
            "dedup": bool(st.session_state.get(dedup_key, row.get("default_dedup", False))),
            "not_applicable": bool(st.session_state.get(na_key, logic_key == "__ignore__")),
        }
    return payload



def _build_template_payload(app_mode: str, header_rows_a: list[dict], header_rows_b: list[dict]) -> dict:
    return {
        "app_mode": app_mode,
        "table_a": _build_template_rows_from_state(header_rows_a, "table_a_header_logic"),
        "table_b": _build_template_rows_from_state(header_rows_b, "table_b_header_logic"),
        "table_a_headers": [str(row.get("header", "")) for row in header_rows_a or []],
        "table_b_headers": [str(row.get("header", "")) for row in header_rows_b or []],
    }



def _save_header_template(template_name: str, payload: dict):
    target = _template_file_path(template_name)
    target.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    (_template_store_dir() / "_last_template_name.txt").write_text(_safe_template_name(template_name), encoding="utf-8")
    (_template_store_dir() / "_last_template.json").write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")



def _load_header_template(template_name: str | None = None):
    if template_name:
        target = _template_file_path(template_name)
    else:
        target = _template_store_dir() / "_last_template.json"
    if not target.exists():
        return None
    try:
        return json.loads(target.read_text(encoding="utf-8"))
    except Exception:
        return None



def _last_template_name() -> str:
    target = _template_store_dir() / "_last_template_name.txt"
    if target.exists():
        value = target.read_text(encoding="utf-8").strip()
        if value:
            return value
    return "last_used"



def _safe_streamlit_rerun():
    rerun_fn = getattr(st, "rerun", None) or getattr(st, "experimental_rerun", None)
    if callable(rerun_fn):
        rerun_fn()


def _header_match_stats(current_headers: list[str], saved_headers: list[str]):
    current_clean = [str(h or "").strip() for h in current_headers or [] if str(h or "").strip()]
    saved_clean = [str(h or "").strip() for h in saved_headers or [] if str(h or "").strip()]
    current_set = set(current_clean)
    saved_set = set(saved_clean)
    overlap = len(current_set & saved_set)
    denom = max(len(saved_set), len(current_set), 1)
    ratio = overlap / denom
    return overlap, ratio, len(current_set), len(saved_set)


def _template_is_compatible(header_rows: list[dict], payload: dict, table_name: str, *, require_strong_match: bool) -> bool:
    if not payload:
        return False
    current_headers = [str(row.get("header", "")) for row in header_rows or []]
    saved_headers = payload.get(f"{table_name}_headers") or []
    if not current_headers:
        return False
    if not saved_headers:
        return not require_strong_match
    overlap, ratio, current_count, saved_count = _header_match_stats(current_headers, saved_headers)
    if require_strong_match:
        return overlap >= 3 and ratio >= 0.60
    return overlap >= 1 and (ratio >= 0.35 or overlap >= min(3, saved_count, current_count))


def _sanitize_loaded_logic_key(header: str, logic_key: str):
    header_text = str(header or "").strip()
    header_lower = re.sub(r"\s+", " ", header_text.lower())
    if any(token in header_lower for token in ["validity date", "expiry", "expiration", "expiry date", "expiration date", "exp date"]):
        return "__ignore__"
    if header_lower in {"no", "no.", "number", "row no", "row no.", "row number"} and logic_key == "contact_no":
        return "__ignore__"
    if header_lower == "birth day" and logic_key == "birthdate":
        return "birth_day"
    if header_lower == "birth month" and logic_key == "birthdate":
        return "birth_month"
    if header_lower == "birth year" and logic_key == "birthdate":
        return "birth_year"
    if logic_key in {"region", "province", "municipality", "barangay", "lgu"}:
        return "__ignore__"
    return logic_key


def _apply_template_to_rows(header_rows: list[dict], key_prefix: str, table_payload: dict):
    if not table_payload:
        return
    for row in header_rows or []:
        saved = table_payload.get(str(row["header"]))
        if not saved:
            continue
        row_id = row["row_id"]
        mapping_key = f"{key_prefix}_mapping_{row_id}"
        finding_key = f"{key_prefix}_finding_{row_id}"
        dedup_key = f"{key_prefix}_dedup_{row_id}"
        na_key = f"{key_prefix}_na_{row_id}"
        logic_key = saved.get("logic_key") or "__ignore__"
        logic_key = _sanitize_loaded_logic_key(str(row.get("header", "")), logic_key)
        st.session_state[mapping_key] = logic_key
        st.session_state[na_key] = bool(saved.get("not_applicable", logic_key == "__ignore__")) or logic_key == "__ignore__"
        st.session_state[finding_key] = bool(saved.get("finding", False)) and not st.session_state[na_key]
        st.session_state[dedup_key] = bool(saved.get("dedup", False)) and not st.session_state[na_key]
        if logic_key == "__ignore__":
            st.session_state[finding_key] = False
            st.session_state[dedup_key] = False



def _header_signature(header_rows: list[dict]) -> str:
    return "|".join(str(row.get("header", "")) for row in header_rows or [])



def _auto_apply_last_template(header_rows: list[dict], key_prefix: str, table_name: str):
    signature = _header_signature(header_rows)
    state_key = f"{key_prefix}_auto_template_signature"
    if not signature or st.session_state.get(state_key) == signature:
        return
    payload = _load_header_template(None)
    if payload and _template_is_compatible(header_rows, payload, table_name, require_strong_match=True):
        _apply_template_to_rows(header_rows, key_prefix, payload.get(table_name, {}))
        app_mode = payload.get("app_mode")
        if app_mode in {"Preset", "Generic"} and "dedup_app_mode" not in st.session_state:
            st.session_state["dedup_app_mode"] = app_mode
    st.session_state[state_key] = signature


def _clear_previous_run_state():
    for key in [
        "fuel_results",
        "fuel_export_zip_bytes",
        "fuel_export_zip_name",
        "fuel_config_snapshot",
        "fuel_last_error",
    ]:
        st.session_state.pop(key, None)


def main():
    st.set_page_config(page_title="streamlit_dedup", layout="wide")
    st.title("streamlit_dedup")
    st.caption("Keeps the original dedup engine and wraps it in a browser UI close to the Tkinter flow.")

    with st.expander("Run note", expanded=True):
        st.write(
            "Upload File A and optional File B, choose sheets/header rows, then run Preview or build an Export ZIP. "
            "This version keeps your dedup/autofix/export logic but replaces Tkinter popups with in-page Streamlit controls."
        )

    engine = load_engine()

    col1, col2 = st.columns(2)
    with col1:
        file_a = st.file_uploader("Excel File A", type=["xlsx", "xlsm", "xls"], key="file_a_uploader")
        path_a = _save_upload(file_a, "A") if file_a is not None else ""
        sheets_a = _safe_list_sheets(engine, path_a)
        sheet_a = st.selectbox("Sheet A", sheets_a or [""], index=0, key="sheet_a_select")
        hdr_a = st.number_input("Header Row A (0-based)", min_value=0, value=0, step=1, key="hdr_a_input")

    with col2:
        file_b = st.file_uploader("Excel File B (optional)", type=["xlsx", "xlsm", "xls"], key="file_b_uploader")
        path_b = _save_upload(file_b, "B") if file_b is not None else ""
        sheets_b = _safe_list_sheets(engine, path_b) if path_b else []

        # Same-workbook cross match support:
        # If File B is not uploaded, the user can still compare Sheet A vs another
        # sheet inside File A (example: CBMS vs ACTIVE LIST in one workbook).
        same_workbook_b = False
        if file_b is None and path_a and len(sheets_a or []) > 1:
            same_sheet_options = [""] + [s for s in (sheets_a or []) if str(s) != str(sheet_a)]
            sheet_b = st.selectbox("Sheet B (optional — same workbook as File A)", same_sheet_options, index=0, key="sheet_b_select")
            if sheet_b:
                path_b = path_a
                sheets_b = sheets_a
                file_b = file_a
                same_workbook_b = True
                st.caption("Using File A again for File B because Sheet B is from the same workbook.")
        else:
            sheet_b = st.selectbox("Sheet B", sheets_b or [""], index=0, key="sheet_b_select")
        hdr_b = st.number_input("Header Row B (0-based)", min_value=0, value=0, step=1, key="hdr_b_input")

    opt1, opt2, opt3, opt4 = st.columns([1.2, 1, 1, 2.2])
    with opt1:
        app_mode = st.radio("Mode", ["Preset", "Generic"], horizontal=True, key="dedup_app_mode")
    with opt2:
        strict_level = st.slider("Strictness", min_value=0, max_value=100, value=80, step=1)
    with opt3:
        include_birth = st.checkbox("Include Birthdate", value=True)
    with opt4:
        if app_mode == "Preset":
            st.info("Preset mode keeps the built-in default behavior, but you can still adjust each detected header before running.")
        else:
            st.info("Generic mode lets you remap headers so the same app can work on other file layouts too.")

    age1, age2, age3, age4 = st.columns([1.2, 1, 1.2, 1])
    with age1:
        enable_min_age = st.checkbox("Use Below Age Limit", value=True, help="Rows younger than this age go to Finding.")
    with age2:
        min_age_limit = st.number_input("Below Age Value", min_value=0, max_value=150, value=18, step=1, disabled=not enable_min_age)
    with age3:
        enable_max_age = st.checkbox("Use Too Old Limit", value=True, help="Rows older than this age go to Finding.")
    with age4:
        max_age_limit = st.number_input("Too Old Value", min_value=0, max_value=150, value=85, step=1, disabled=not enable_max_age)

    if include_birth and enable_min_age and enable_max_age and int(min_age_limit) > int(max_age_limit):
        st.warning("Below-age value is higher than too-old value. The app will still run, but this setting is unusual.")

    headers_a = _read_headers_from_upload(file_a, sheet_a, hdr_a + 1) if file_a and sheet_a else []
    headers_b = _read_headers_from_upload(file_b, sheet_b, hdr_b + 1) if file_b and sheet_b else []

    header_rows_a = _build_detected_header_rows(engine, headers_a, "A")
    header_rows_b = _build_detected_header_rows(engine, headers_b, "B")
    _auto_apply_last_template(header_rows_a, "table_a_header_logic", "table_a")
    _auto_apply_last_template(header_rows_b, "table_b_header_logic", "table_b")

    control_rows_a = []
    control_rows_b = []
    finding_selected = set()
    dedupe_selected = set()

    with st.expander("Header controls for Finding and Dedup", expanded=False):
        st.caption(
            "Each detected header can be mapped, turned on for Finding, turned on for Dedup, or marked Not Applicable. "
            "Not Applicable means the data may stay in the file, but that header will not affect the logic. "
            "Driver's License Number is now removed from active Streamlit logic choices."
        )
        if headers_a:
            st.markdown("**Detected table headers - A**")
            st.code(" | ".join(headers_a[:60]) + (" | ..." if len(headers_a) > 60 else ""))
        if headers_b:
            st.markdown("**Detected table headers - B**")
            st.code(" | ".join(headers_b[:60]) + (" | ..." if len(headers_b) > 60 else ""))

        if header_rows_a or header_rows_b:
            if header_rows_a:
                control_rows_a = _render_detected_header_controls("Table A header logic", header_rows_a, "table_a_header_logic", app_mode)
                fa, da = _collect_logic_selections(control_rows_a)
                finding_selected.update(fa)
                dedupe_selected.update(da)
            if header_rows_a and header_rows_b:
                st.divider()
            if header_rows_b:
                control_rows_b = _render_detected_header_controls("Table B header logic", header_rows_b, "table_b_header_logic", app_mode)
                fb, db = _collect_logic_selections(control_rows_b)
                finding_selected.update(fb)
                dedupe_selected.update(db)

            template_cols = st.columns([1.6, 1, 1.4])
            template_name = template_cols[0].text_input("Save template name", value=st.session_state.get("header_template_name", _last_template_name()), key="header_template_name")
            save_template = template_cols[1].button("Save template", use_container_width=True)
            load_template = template_cols[2].button("Load saved template", use_container_width=True)
            st.caption("Saved template remembers your header mapping, Finding, Dedup, and Not Applicable choices for the next run.")

            if save_template:
                payload = _build_template_payload(app_mode, header_rows_a, header_rows_b)
                _save_header_template(template_name, payload)
                st.success(f"Template saved: {_safe_template_name(template_name)}")

            if load_template:
                payload = _load_header_template(template_name)
                table_a_ok = _template_is_compatible(header_rows_a, payload, "table_a", require_strong_match=False) if header_rows_a else True
                table_b_ok = _template_is_compatible(header_rows_b, payload, "table_b", require_strong_match=False) if header_rows_b else True
                if payload and table_a_ok and table_b_ok:
                    _apply_template_to_rows(header_rows_a, "table_a_header_logic", payload.get("table_a", {}))
                    _apply_template_to_rows(header_rows_b, "table_b_header_logic", payload.get("table_b", {}))
                    if payload.get("app_mode") in {"Preset", "Generic"}:
                        st.session_state["dedup_app_mode"] = payload["app_mode"]
                    st.success(f"Template loaded: {_safe_template_name(template_name)}")
                    _safe_streamlit_rerun()
                elif payload:
                    st.warning("Saved template does not match the current headers closely enough. Load a better template or save a new one for this file.")
                else:
                    st.warning("Saved template not found yet.")
        else:
            st.caption("No headers detected yet, so the fallback canonical controls are shown.")
            finding_selected = _render_checkbox_grid(
                "Finding: mark row as Finding when these fields are missing",
                FINDING_FIELD_ORDER,
                FINDING_FIELD_LABELS,
                DEFAULT_FINDING_FIELDS,
                "finding_field",
            )
            st.divider()
            dedupe_selected = _render_checkbox_grid(
                "Dedup: use these fields in match logic and reason text",
                DEDUPE_FIELD_ORDER,
                DEDUPE_FIELD_LABELS,
                DEFAULT_DEDUPE_FIELDS,
                "dedupe_field",
            )

        has_manual_controls = bool(control_rows_a or control_rows_b)
        if not dedupe_selected and not has_manual_controls:
            dedupe_selected = set(DEFAULT_DEDUPE_FIELDS)
        if not finding_selected and not has_manual_controls:
            finding_selected = set(DEFAULT_FINDING_FIELDS)
        finding_selected = _enforce_optional_location_finding(finding_selected, control_rows_a, control_rows_b)
        finding_header_rules_a = _collect_checked_header_finding_rules(control_rows_a)
        finding_header_rules_b = _collect_checked_header_finding_rules(control_rows_b)
        dedup_header_rules_a = _collect_checked_header_dedup_rules(control_rows_a)
        dedup_header_rules_b = _collect_checked_header_dedup_rules(control_rows_b)

        st.info(
            "Finding watches: "
            + _format_logic_field_labels(finding_selected, FINDING_FIELD_LABELS, FINDING_FIELD_ORDER)
            + "\n\nDedup compares: "
            + _format_logic_field_labels(dedupe_selected, DEDUPE_FIELD_LABELS, DEDUPE_FIELD_ORDER)
        )
        checked_dedup_headers = [r.get("header", "") for r in (dedup_header_rules_a + dedup_header_rules_b)]
        if checked_dedup_headers:
            st.caption(
                "Dedup checkbox active: fuzzy/similar matching will also check selected header(s): "
                + ", ".join(list(dict.fromkeys([str(h) for h in checked_dedup_headers if str(h).strip()]))[:12])
            )
            if not any(_dedup_checkbox_is_identity_rule(r) for r in (dedup_header_rules_a + dedup_header_rules_b)):
                st.warning(
                    "Dedup columns selected, but no identity-style field is selected. "
                    "Choose at least Name, Birthdate, Contact No., License No., or Full Name so the app can avoid false duplicates."
                )
        st.caption("Tip: for stable dedup, keep at least First Name, Last Name, and Birth Year checked. Location columns are support evidence; they will not create duplicates by themselves.")

    with st.expander("Large-file speed options", expanded=True):
        fast_review_mode = st.checkbox(
            "Fast Review Mode",
            value=True,
            help=(
                "Recommended for 500K–1M rows. Run Preview/Review processes only a sample first, "
                "so you can verify header mapping, Finding, Dedup, fuzzy, swap, and cross-match behavior faster. "
                "Build Export ZIP still processes the full file."
            ),
        )
        review_row_limit = st.number_input(
            "Rows to process during Review per file",
            min_value=1000,
            max_value=200000,
            value=30000,
            step=5000,
            disabled=not fast_review_mode,
            help="Higher = more accurate test, slower. For first checking, 30,000 is usually enough.",
        )
        st.caption("For final full data, click **Build Export ZIP**. For fast checking, click **Run Preview**.")

    btn1, btn2 = st.columns(2)
    run_preview = btn1.button("Run Preview / Review Sample", type="primary", use_container_width=True)
    run_export = btn2.button("Build Export ZIP Full Data", use_container_width=True)

    results = st.session_state.get("fuel_results")
    config_snapshot = {
        "file_a_name": file_a.name if file_a is not None else "",
        "file_b_name": (file_b.name if file_b is not None and not locals().get("same_workbook_b", False) else (f"{file_a.name}::{sheet_b}" if locals().get("same_workbook_b", False) and file_a is not None and sheet_b else "")),
        "path_a": path_a,
        "path_b": path_b,
        "sheet_a": sheet_a,
        "sheet_b": sheet_b,
        "hdr_a": int(hdr_a),
        "hdr_b": int(hdr_b),
        "strict_level": int(strict_level),
        "include_birth": bool(include_birth),
        "enable_min_age": bool(enable_min_age),
        "min_age_limit": int(min_age_limit),
        "enable_max_age": bool(enable_max_age),
        "max_age_limit": int(max_age_limit),
        "finding_fields": sorted(finding_selected),
        "dedupe_fields": sorted(dedupe_selected),
        "mode": app_mode,
        "fast_review_mode": bool(fast_review_mode),
        "review_row_limit": int(review_row_limit),
        "table_a_logic_signature": _control_rows_signature(control_rows_a),
        "table_b_logic_signature": _control_rows_signature(control_rows_b),
    }

    if run_preview or run_export:
        if not path_a and not path_b:
            st.error("Upload at least File A or File B first.")
        else:
            _clear_previous_run_state()
            try:
                review_max_rows = int(review_row_limit) if (run_preview and fast_review_mode) else None
                prepared_a, prepared_sheet_a, prepared_hdr_a, notices_a = _prepare_run_file(
                    file_a, path_a, sheet_a, hdr_a, control_rows_a, "A", max_rows=review_max_rows
                ) if path_a and sheet_a else (path_a, sheet_a, hdr_a, [])
                prepared_b, prepared_sheet_b, prepared_hdr_b, notices_b = _prepare_run_file(
                    file_b, path_b, sheet_b, hdr_b, control_rows_b, "B", max_rows=review_max_rows
                ) if path_b and sheet_b else (path_b, sheet_b, hdr_b, [])

                for notice in list(dict.fromkeys((notices_a or []) + (notices_b or []))):
                    st.caption(f"• {notice}")

                _apply_streamlit_field_overrides(engine, finding_selected, dedupe_selected)
                results = _run_engine(
                    engine,
                    prepared_a,
                    prepared_b,
                    prepared_sheet_a,
                    prepared_sheet_b,
                    prepared_hdr_a,
                    prepared_hdr_b,
                    strict_level,
                    include_birth,
                    enable_min_age,
                    int(min_age_limit),
                    enable_max_age,
                    int(max_age_limit),
                )
                meta_a = st.session_state.get("header_restore_meta_A", {})
                meta_b = st.session_state.get("header_restore_meta_B", {})
                results = _restore_imported_headers_results(results, meta_a, meta_b)
                results = _apply_finding_reason_safety_to_results(results, finding_selected)
                results = _apply_checked_header_missing_finding_to_results(
                    results,
                    finding_header_rules_a,
                    finding_header_rules_b,
                )
                results = _apply_checked_header_fuzzy_dedup_to_results(
                    results,
                    dedup_header_rules_a,
                    dedup_header_rules_b,
                )
                results = _remove_streamlit_internal_safe_placeholders_results(results)
                st.session_state["fuel_results"] = results
                st.session_state["fuel_config_snapshot"] = config_snapshot

                if run_export:
                    _restore_imported_headers_engine_outputs(engine, meta_a, meta_b)
                    _apply_finding_reason_safety_to_engine(engine, finding_selected)
                    _apply_checked_header_missing_finding_to_engine(
                        engine,
                        finding_header_rules_a,
                        finding_header_rules_b,
                    )
                    _apply_checked_header_fuzzy_dedup_to_engine(
                        engine,
                        dedup_header_rules_a,
                        dedup_header_rules_b,
                    )
                    export_dir = _get_session_dir() / "exports"
                    for old in export_dir.glob("*"):
                        try:
                            old.unlink()
                        except Exception:
                            pass
                    prefix, tag = _build_prefix_and_tag(config_snapshot["file_a_name"], config_snapshot["file_b_name"])
                    paths = engine.export_outputs(str(export_dir), prefix, tag, export_cross=False)
                    zip_name = f"{prefix}_{tag}_EXPORT.zip"
                    zip_bytes = _zip_paths(paths, zip_name)
                    st.session_state["fuel_export_zip_bytes"] = zip_bytes
                    st.session_state["fuel_export_zip_name"] = zip_name
                    st.success("Export ZIP is ready.")
                else:
                    if run_preview and fast_review_mode:
                        st.success(f"Review sample complete — processed up to {int(review_row_limit):,} rows per file.")
                    else:
                        st.success("Preview complete.")
            except Exception as exc:
                st.session_state["fuel_last_error"] = str(exc)
                st.exception(exc)
                results = None

    if st.session_state.get("fuel_export_zip_bytes"):
        st.download_button(
            "Download Export ZIP",
            data=st.session_state["fuel_export_zip_bytes"],
            file_name=st.session_state.get("fuel_export_zip_name", "streamlit_dedup_export.zip"),
            mime="application/zip",
            use_container_width=True,
        )

    if results:
        last_config_snapshot = st.session_state.get("fuel_config_snapshot")
        if last_config_snapshot != config_snapshot:
            st.warning("Header/file settings changed after the last run. These results are outdated — rerun needed.")
        clean_ab_df = results.get("clean_ab")
        lack_ab_df = results.get("lack_ab")
        if (clean_ab_df is None or len(clean_ab_df) == 0) and lack_ab_df is not None and len(lack_ab_df) > 0:
            reason_col = "Lack_Reason" if "Lack_Reason" in lack_ab_df.columns else None
            if reason_col:
                top_reasons = lack_ab_df[reason_col].astype(str).value_counts().head(3)
                summary = "; ".join(f"{reason} ({count})" for reason, count in top_reasons.items())
                st.warning("Clean A+B is empty because rows were pushed to Finding A+B. Top reasons: " + summary)
            else:
                st.warning("Clean A+B is empty because rows were pushed to Finding A+B.")

        clean_ab_count = 0 if results.get("clean_ab") is None else len(results.get("clean_ab"))
        dedup_ab_count = 0 if results.get("dup_ab") is None else len(results.get("dup_ab"))
        finding_ab_count = 0 if results.get("lack_ab") is None else len(results.get("lack_ab"))
        cross_dup_ab_count = 0 if results.get("cross_dup_ab") is None else len(results.get("cross_dup_ab"))
        overall_file_ab_count = _safe_source_row_count(path_a, sheet_a, hdr_a) + _safe_source_row_count(path_b, sheet_b, hdr_b)
        total_main_ab_count = clean_ab_count + dedup_ab_count + finding_ab_count
        total_dedup_finding_ab_count = dedup_ab_count + finding_ab_count

        counts = [
            {"View": "Overall File A+B", "Rows": overall_file_ab_count},
            {"View": "Total Clean+Dedup+Finding A+B", "Rows": total_main_ab_count},
            {"View": "Total Dedup+Finding A+B", "Rows": total_dedup_finding_ab_count},
            {"View": "Clean A+B", "Rows": clean_ab_count},
            {"View": "Dedup A+B", "Rows": dedup_ab_count},
            {"View": "Finding A+B", "Rows": finding_ab_count},
            {"View": "Cross Duplicate A+B", "Rows": cross_dup_ab_count},
        ]
        st.subheader("Result counts")
        st.dataframe(pd.DataFrame(counts), use_container_width=True, hide_index=True)

        tabs = st.tabs(["Clean A+B", "Dedup A+B", "Finding A+B", "Cross Duplicate A+B"])
        tab_map = [
            ("Clean A+B", "clean_ab"),
            ("Dedup A+B", "dup_ab"),
            ("Finding A+B", "lack_ab"),
            ("Cross Duplicate A+B", "cross_dup_ab"),
        ]
        for tab, (label, key) in zip(tabs, tab_map):
            with tab:
                _display_result_block(label, results.get(key), key)


if __name__ == "__main__":
    main()
